#include <cuda.h>
#include <stdint.h>
#include <stdbool.h>

#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    bool is_leaf;
    int num_keys;
} knode;

__global__ void 
findK(long height,
      knode *knodesD,
      long knodes_elem,
      record *recordsD,
      long *currKnodeD,
      long *offsetD,
      int *keysD, 
      record *ansD)
{
    int thid = threadIdx.x;
    int bid = blockIdx.x;

    int i;
    for(i = 0; i < height; i++){
        if((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] && 
           (knodesD[currKnodeD[bid]].keys[thid+1] > keysD[bid])){
            if(knodesD[offsetD[bid]].indices[thid] < knodes_elem){
                offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
            }
        }

        __syncthreads();

        if(thid==0){
            currKnodeD[bid] = offsetD[bid];
        }

        __syncthreads();
    }

    if(knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]){
        ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
    }
}

