	err = cudaMemcpy(recordsD, records, records_mem, cudaMemcpyHostToDevice);
	if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy recordsD failed\n"); exit(1); }

	err = cudaMemcpy(knodesD, knodes, knodes_mem, cudaMemcpyHostToDevice);
	if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy knodesD failed\n"); exit(1); }

	err = cudaMemcpy(currKnodeD, currKnode, count*sizeof(long), cudaMemcpyHostToDevice);
	if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy currKnodeD failed\n"); exit(1); }

