	if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy keysD failed\n"); exit(1); }

	err = cudaMemcpy(ansD, ans, count*sizeof(record), cudaMemcpyHostToDevice);
	if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy ansD failed\n"); exit(1); }

