int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
    int in, hid, out;
    float out_err, hid_err;
    float sum;

    in = net->input_n;
    hid = net->hidden_n;
    out = net->output_n;

    int num_blocks = in / BLOCK_SIZE;

    float *input_weights_one_dim;
    float *input_weights_prev_one_dim;
    float *partial_sum;

    input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
    input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
    partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

    int m = 0;
    for (int k = 0; k <= in; k++) {
        for (int j = 0; j <= hid; j++) {
            input_weights_one_dim[m] = net->input_weights[k][j];
            input_weights_prev_one_dim[m] = net->input_prev_weights[k][j];
            m++;
        }
    }

    float *d_input_units;
    float *d_input_hidden;
    float *d_output_hidden;
    float *d_hidden_partial_sum;
    float *d_hidden_delta;
    float *d_input_prev_weights;

    cudaMalloc(&d_input_units, (in + 1) * sizeof(float));
    cudaMalloc(&d_input_hidden, (in + 1) * (hid + 1) * sizeof(float));
    cudaMalloc(&d_output_hidden, (hid + 1) * sizeof(float));
    cudaMalloc(&d_hidden_partial_sum, num_blocks * WIDTH * sizeof(float));
    cudaMalloc(&d_hidden_delta, (hid + 1) * sizeof(float));
    cudaMalloc(&d_input_prev_weights, (in + 1) * (hid + 1) * sizeof(float));

    cudaMemcpy(d_input_units, net->input_units, (in + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_input_hidden, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_input_prev_weights, input_weights_prev_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);

    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid(1, num_blocks);

    bpnn_layerforward_ocl<<<grid, block>>>(d_input_units, d_output_hidden, d_input_hidden, d_hidden_partial_sum, in, hid);
    cudaDeviceSynchronize();

    cudaMemcpy(partial_sum, d_hidden_partial_sum, num_blocks * WIDTH * sizeof(float), cudaMemcpyDeviceToHost);

    for (int j = 1; j <= hid; j++) {
        sum = 0.0;
        for (int k = 0; k < num_blocks; k++) {
            sum += partial_sum[k * hid + j-1];
        }
        sum += net->input_weights[0][j];
        net->hidden_units[j] = squash(sum);
    }

    bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
    bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
    bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
    bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

    cudaMemcpy(d_hidden_delta, net->hidden_delta, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_input_prev_weights, input_weights_prev_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(d_input_hidden, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);

    bpnn_adjust_weights_ocl<<<grid, block>>>(d_hidden_delta, hid, d_input_units, in, d_input_hidden, d_input_prev_weights);
    cudaDeviceSynchronize();

    cudaMemcpy(net->input_units, d_input_units, (in + 1) * sizeof(float), cudaMemcpyDeviceToHost);
    cudaMemcpy(input_weights_one_dim, d_input_hidden, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);

    m = 0;
    for (int k = 0; k <= in; k++) {
        for (int j = 0; j <= hid; j++) {
            net->input_weights[k][j] = input_weights_one_dim[m];
            m++;
        }
    }

    cudaFree(d_input_units);
    cudaFree(d_input_hidden);
    cudaFree(d_output_hidden);
    cudaFree(d_hidden_partial_sum);
    cudaFree(d_hidden_delta);
    cudaFree(d_input_prev_weights);

    free(input_weights_prev_one_dim);
    free(partial_sum);
    free(input_weights_one_dim);

    *eo = out_err;
    *eh = hid_err;

    return 0;
}

