void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  float sum;
  int j, k;
  l1[0] = 1.0;
  for (j = 1; n2 >= j; j++) {
    sum = 0.0;
    for (k = 0; n1 >= k; k++) {	
      sum += conn[k][j] * l1[k]; 
