void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  float sum;
  int j, k;
  l1[0] = 1.0;
  for (j = 1; n2 >= j; j++) {
    sum = 0.0;
    for (k = 0; n1 >= k; k++) {	
      sum = sum + (conn[k][j] * l1[k]); 
    }
    l2[j] = squash(sum);
  }
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err)  
{
  int j;
  float o, t, errsum;
  errsum = 0.0;
  for (j = 1; nj >= j; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0 - o) * (t - o);
    errsum = errsum + (ABS(delta[j]));
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err)
{
  int j, k;
  float h, sum, errsum;
  errsum = 0.0;
  for (j = 1; nh >= j; j++) {
    h = hidden[j];
    sum = 0.0;
    for (k = 1; no >= k; k++) {
      sum = sum + (delta_o[k] * who[j][k]);
    }
    delta_h[j] = h * (1.0 - h) * sum;
    errsum = errsum + (ABS(delta_h[j]));
  }
  *err = errsum;
}

