#ifdef PROFILING
#include "timer.h"
#endif

#ifdef TIMING
#include "timing.h"
#endif

#include "util.h"

#define MAX_THREADS_PER_BLOCK 256

struct Node {
    int starting;
    int no_of_edges;
};

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

void run_bfs_cpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost_ref)
{
    char stop;
    int k = 0;
    do {
        stop=false;
        for(int tid = 0; tid < no_of_nodes; tid++ ) {
            if (h_graph_mask[tid] == true) {
                h_graph_mask[tid]=false;
                for(int i=h_graph_nodes[tid].starting; (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting) > i; i++) {
                    int id = h_graph_edges[i];
                    if(!h_graph_visited[id]) {
                        h_cost_ref[id]=h_cost_ref[tid]+1;
                        h_updating_graph_mask[id]=true;
                    }
                }
            }
        }

        for(int tid=0; no_of_nodes > tid ; tid++ ) {
            if (h_updating_graph_mask[tid] == true) {
                h_graph_mask[tid]=true;
                h_graph_visited[tid]=true;
                stop=true;
                h_updating_graph_mask[tid]=false;
            }
        }
        k++;
    } while(stop);
}

void run_bfs_gpu(int no_of_nodes, Node *h_graph_nodes, int edge_list_size,
                 int *h_graph_edges, char *h_graph_mask, char *h_updating_graph_mask,
                 char *h_graph_visited, int *h_cost)
throw(std::string)
{
    char h_over;
    Node *d_graph_nodes;
    int *d_graph_edges;
    char *d_graph_mask, *d_updating_graph_mask, *d_graph_visited, *d_over;
    int *d_cost;

    try {
#ifdef TIMING
        gettimeofday(&tv_total_start, NULL);
#endif

#ifdef TIMING
        gettimeofday(&tv_mem_alloc_start, NULL);
        tvsub(&tv_mem_alloc_start, &tv_total_start, &tv);
        init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

        cudaMalloc(&d_graph_nodes, no_of_nodes*sizeof(Node));
        cudaMalloc(&d_graph_edges, edge_list_size*sizeof(int));
        cudaMalloc(&d_graph_mask, no_of_nodes*sizeof(char));
        cudaMalloc(&d_updating_graph_mask, no_of_nodes*sizeof(char));
        cudaMalloc(&d_graph_visited, no_of_nodes*sizeof(char));
        cudaMalloc(&d_cost, no_of_nodes*sizeof(int));
        cudaMalloc(&d_over, sizeof(char));

        cudaMemcpy(d_graph_nodes, h_graph_nodes, no_of_nodes*sizeof(Node), cudaMemcpyHostToDevice);
        cudaMemcpy(d_graph_edges, h_graph_edges, edge_list_size*sizeof(int), cudaMemcpyHostToDevice);
        cudaMemcpy(d_graph_mask, h_graph_mask, no_of_nodes*sizeof(char), cudaMemcpyHostToDevice);
        cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, no_of_nodes*sizeof(char), cudaMemcpyHostToDevice);
        cudaMemcpy(d_graph_visited, h_graph_visited, no_of_nodes*sizeof(char), cudaMemcpyHostToDevice);
        cudaMemcpy(d_cost, h_cost, no_of_nodes*sizeof(int), cudaMemcpyHostToDevice);

#ifdef PROFILING
        timer kernel_timer;
        double kernel_time_val = 0.0;
        kernel_timer.reset();
        kernel_timer.start();
#endif

        int block_size = 512;
        if (no_of_nodes < block_size) block_size = no_of_nodes;
        int num_blocks = (no_of_nodes + block_size - 1) / block_size;

        do {
            h_over = false;
            cudaMemcpy(d_over, &h_over, sizeof(char), cudaMemcpyHostToDevice);

            BFS_1<<<num_blocks, block_size>>>(d_graph_nodes, d_graph_edges, d_graph_mask, d_updating_graph_mask, d_graph_visited, d_cost, no_of_nodes);

            BFS_2<<<num_blocks, block_size>>>(d_graph_mask, d_updating_graph_mask, d_graph_visited, d_over, no_of_nodes);

            cudaMemcpy(&h_over, d_over, sizeof(char), cudaMemcpyDeviceToHost);
        } while(h_over);

        cudaDeviceSynchronize();

#ifdef PROFILING
        kernel_timer.stop();
        kernel_time_val = kernel_timer.getTimeInSeconds();
#endif

        cudaMemcpy(h_cost, d_cost, no_of_nodes*sizeof(int), cudaMemcpyDeviceToHost);

#ifdef TIMING
        gettimeofday(&tv_close_start, NULL);
#endif

#ifdef PROFILING
        std::cout<<"kernel time(s):"<<kernel_time_val<<std::endl;
#endif

        cudaFree(d_graph_nodes);
        cudaFree(d_graph_edges);
        cudaFree(d_graph_mask);
        cudaFree(d_updating_graph_mask);
        cudaFree(d_graph_visited);
        cudaFree(d_cost);
        cudaFree(d_over);

    } catch(std::string msg) {
        cudaFree(d_graph_nodes);
        cudaFree(d_graph_edges);
        cudaFree(d_graph_mask);
        cudaFree(d_updating_graph_mask);
        cudaFree(d_graph_visited);
        cudaFree(d_cost);
        cudaFree(d_over);
        std::string e_str = "in run_transpose_gpu -> ";
        e_str += msg;
        throw(e_str);
    }
#ifdef TIMING
        gettimeofday(&tv_close_end, NULL);
        tvsub(&tv_close_end, &tv_close_start, &tv);
        close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
        tvsub(&tv_close_end, &tv_total_start, &tv);
        total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

        printf("Init: %f\n", init_time);
        printf("MemAlloc: %f\n", mem_alloc_time);
        printf("HtoD: %f\n", h2d_time);
        printf("Exec: %f\n", kernel_time);
        printf("DtoH: %f\n", d2h_time);
        printf("Close: %f\n", close_time);
        printf("Total: %f\n", total_time);
#endif

    return ;
}

void Usage(int argc, char**argv)
{
    fprintf(stderr,"Usage: %s <input_file> [-p platform] [-d device] [-t gpu(0)/cpu(1)]\n", argv[0]);
}

int work_group_size = 512;

int main(int argc, char * argv[])
{
    int no_of_nodes;
    int edge_list_size;
    FILE *fp;
    Node* h_graph_nodes;
    char *h_graph_mask, *h_updating_graph_mask, *h_graph_visited;
    try {
        char *input_f;
        if(2 > argc) {
            Usage(argc, argv);
            exit(0);
        }

        // Parse simple CUDA args if needed, though original used OpenCL specific flags
        for (int i=0; i < argc; ++i) {
            if (argv[i][1] == 'g' && i+1 < argc) {
                sscanf(argv[i+1], "%d", &work_group_size);
            }
        }

        input_f = argv[1];
        printf("Reading File\n");

        fp = fopen(input_f,"r");
        if(!fp) {
            printf("Error Reading graph file\n");
            return 0;
        }

        int source = 0;

        fscanf(fp,"%d",&no_of_nodes);

        int num_of_blocks = 1;
        int num_of_threads_per_block = no_of_nodes;

        if(MAX_THREADS_PER_BLOCK < no_of_nodes) {
            num_of_blocks = (int)ceil(no_of_nodes/(double)MAX_THREADS_PER_BLOCK);
            num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
        }
        work_group_size = num_of_threads_per_block;

        h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
        h_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
        h_updating_graph_mask = (char*) malloc(sizeof(char)*no_of_nodes);
        h_graph_visited = (char*) malloc(sizeof(char)*no_of_nodes);

        int start, edgeno;

        for(int i = 0; no_of_nodes > i; i++) {
            fscanf(fp,"%d %d",&start,&edgeno);
            h_graph_nodes[i].starting = start;
            h_graph_nodes[i].no_of_edges = edgeno;
            h_graph_mask[i]=false;
            h_updating_graph_mask[i]=false;
            h_graph_visited[i]=false;
        }

        fscanf(fp,"%d",&source);
        source=0;

        h_graph_mask[source]=true;
        h_graph_visited[source]=true;
        fscanf(fp,"%d",&edge_list_size);
        int id,cost;
        int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
        for(int i=0; edge_list_size > i ; i++) {
            fscanf(fp,"%d",&id);
            fscanf(fp,"%d",&cost);
            h_graph_edges[i] = id;
        }

        if(fp)
            fclose(fp);

        int	*h_cost = (int*) malloc(sizeof(int)*no_of_nodes);
        int *h_cost_ref = (int*)malloc(sizeof(int)*no_of_nodes);
        for(int i=0; i<no_of_nodes; i++) {
            h_cost[i]=-1;
            h_cost_ref[i] = -1;
        }
        h_cost[source]=0;
        h_cost_ref[source]=0;

        run_bfs_gpu(no_of_nodes,h_graph_nodes,edge_list_size,h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost);

        for(int i = 0; no_of_nodes > i; i++) {
            h_graph_mask[i]=false;
            h_updating_graph_mask[i]=false;
            h_graph_visited[i]=false;
        }

        source=0;
        h_graph_mask[source]=true;
        h_graph_visited[source]=true;
        run_bfs_cpu(no_of_nodes,h_graph_nodes,edge_list_size,h_graph_edges, h_graph_mask, h_updating_graph_mask, h_graph_visited, h_cost_ref);

        compare_results<int>(h_cost_ref, h_cost, no_of_nodes);

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
        free(h_graph_edges);
        free(h_cost);
        free(h_cost_ref);

    } catch(std::string msg) {
        std::cout<<"--cambine: exception in main ->"<<msg<<std::endl;

        free(h_graph_nodes);
        free(h_graph_mask);
        free(h_updating_graph_mask);
        free(h_graph_visited);
    }

    return 0;
}

