        int *center = &(buffer->data[midOffset + i * buffer->SIZE_X + localId]);
        if (flag == 0) {
            *center -= (previous + next) / 2;
        } else if (flag == 1) {
            *center += (previous + next + 2) / 4;
        }
    }

    if (localId < finalCount) {
        const int previous = buffer->data[prevOffset + finalOffset + localId];
        const int next = buffer->data[nextOffset + finalOffset + localId];
        int *center = &(buffer->data[midOffset + finalOffset + localId]);

