void launchFDWT53Kernel(int WIN_SX, int WIN_SY, void *in, void *out, int sx, int sy) {
    const int steps = (sy / (15 * WIN_SY)) + ((sy % (15 * WIN_SY)) ? 1 : 0);

    int gx = (sx / WIN_SX) + ((sx % WIN_SX) ? 1 : 0);
    int gy = (sy / (WIN_SY * steps)) + ((sy % (WIN_SY * steps)) ? 1 : 0);

    printf("sliding steps = %d , gx = %d , gy = %d \n", steps, gx, gy);

    dim3 globalWorkSize(gx * WIN_SX, gy * 1, 1);
    dim3 localWorkSize(WIN_SX, 1, 1);

    cl_fdwt53Kernel<<<globalWorkSize, localWorkSize>>>( (int*)in, (int*)out, sx, sy, steps, WIN_SX, WIN_SY);

    printf("cl_fdwt53Kernel in launchFDW53Kernel has finished\n");
}

