namespace dwt_cuda {
    void fdwt53(int *in, int *out, int sizeX, int sizeY, int levels) {
        if(sizeX >= 960) {
            const int steps = (sizeY / (15 * 8)) + ((sizeY % (15 * 8)) ? 1 : 0);
            int gx = (sizeX / 192) + ((sizeX % 192) ? 1 : 0);
            int gy = (sizeY / (8 * steps)) + ((sizeY % (8 * steps)) ? 1 : 0);
            dim3 globalWorkSize(gx * 192, gy * 1, 1);
            dim3 localWorkSize(192, 1, 1);
            cl_fdwt53Kernel<<<globalWorkSize, localWorkSize>>>(in, out, sizeX, sizeY, steps, 192, 8);
        } else if (sizeX >= 480) {
            const int steps = (sizeY / (15 * 8)) + ((sizeY % (15 * 8)) ? 1 : 0);
            int gx = (sizeX / 128) + ((sizeX % 128) ? 1 : 0);
            int gy = (sizeY / (8 * steps)) + ((sizeY % (8 * steps)) ? 1 : 0);
            dim3 globalWorkSize(gx * 128, gy * 1, 1);
            dim3 localWorkSize(128, 1, 1);
            cl_fdwt53Kernel<<<globalWorkSize, localWorkSize>>>(in, out, sizeX, sizeY, steps, 128, 8);
        } else {
            const int steps = (sizeY / (15 * 8)) + ((sizeY % (15 * 8)) ? 1 : 0);
            int gx = (sizeX / 64) + ((sizeX % 64) ? 1 : 0);
            int gy = (sizeY / (8 * steps)) + ((sizeY % (8 * steps)) ? 1 : 0);
            dim3 globalWorkSize(gx * 64, gy * 1, 1);
            dim3 localWorkSize(64, 1, 1);
            cl_fdwt53Kernel<<<globalWorkSize, localWorkSize>>>(in, out, sizeX, sizeY, steps, 64, 8);
        }

        if (levels > 1) {
            const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 : 0);
            const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 : 0);
            cudaMemcpy(in, out, llSizeX * llSizeY * sizeof(int), cudaMemcpyDeviceToDevice);
            fdwt53(in, out, llSizeX, llSizeY, levels - 1);
        }
    }
}

