#define THREADS 256
#define BOUNDARY_X 2

namespace dwt_cuda {

inline int divRndUp(int n, int d) {
    return (n / d) + ((n % d) ? 1 : 0);
}

__device__ void storeComponents(int *d_r, int *d_g, int *d_b, int r, int g, int b, int pos) {
    d_r[pos] = r - 128;
    d_g[pos] = g - 128;
    d_b[pos] = b - 128;
}

__device__ void storeComponent(int *d_c, int c, int pos) {
    d_c[pos] = c - 128;
}

__global__ void c_CopySrcToComponents(int *d_r, int *d_g, int *d_b, unsigned char *cl_d_src, int pixels) {
    int x = threadIdx.x;
    int gX = blockDim.x * blockIdx.x;

    extern __shared__ unsigned char sData[THREADS * 3];

    if (gX * 3 + 3 * x + 2 < pixels * 3) {
        sData[3 * x + 0] = cl_d_src[gX * 3 + 3 * x + 0];
        sData[3 * x + 1] = cl_d_src[gX * 3 + 3 * x + 1];
        sData[3 * x + 2] = cl_d_src[gX * 3 + 3 * x + 2];
    }

    __syncthreads();

    int r, g, b;
    int offset = x * 3;
    r = (int)(sData[offset]);
    g = (int)(sData[offset + 1]);
    b = (int)(sData[offset + 2]);

    int globalOutputPosition = gX + x;
    if (pixels > globalOutputPosition) {
        storeComponents(d_r, d_g, d_b, r, g, b, globalOutputPosition);
    }
}

__global__ void c_CopySrcToComponent(int *d_c, unsigned char *cl_d_src, int pixels) {
    int x = threadIdx.x;
    int gX = blockDim.x * blockIdx.x;

    extern __shared__ unsigned char sData[THREADS];

    if (gX + x < pixels) {
        sData[x] = cl_d_src[gX + x];
    }

    __syncthreads();

    int c = (int)(sData[x]);

    int globalOutputPosition = gX + x;
    if (pixels > globalOutputPosition) {
        storeComponent(d_c, c, globalOutputPosition);
    }
}

static __device__ void mirror(int *d, const int sizeD) {
    if (sizeD <= (*d)) {
        (*d) = 2 * sizeD - 2 - (*d);
    } else if (0 > (*d)) {
        (*d) = -(*d);
    }
}

struct VerticalDWTPixelIO {
    bool CHECKED;
    int end, stride;
};

__device__ int initialize_PixelIO(VerticalDWTPixelIO *pIO, bool CHECK, const int sizeX, const int sizeY, int firstX, int firstY) {
    pIO->CHECKED = CHECK;
    pIO->end = pIO->CHECKED ? (sizeY * sizeX + firstX) : 0;
    pIO->stride = sizeX;
    return firstX + sizeX * firstY;
}

struct VerticalDWTPixelLoader {
    bool CHECKED;
    int last;
};

__device__ void init_PixelLoader(VerticalDWTPixelLoader *loader, const int sizeX, const int sizeY, int firstX, const int firstY, VerticalDWTPixelIO *pIO, bool CHECK) {
    mirror(&firstX, sizeX);
    loader->last = initialize_PixelIO(pIO, CHECK, sizeX, sizeY, firstX, firstY) - sizeX;
}

__device__ void clear_PixelLoader(VerticalDWTPixelLoader *pLoader, VerticalDWTPixelIO *pIO) {
    pLoader->last = 0;
    pIO->end = 0;
    pIO->stride = 0;
}

__device__ int loadFrom(VerticalDWTPixelLoader *pLoader, const int *input, VerticalDWTPixelIO *pIO, int CHECK) {
    pLoader->last += pIO->stride;
    if (CHECK && (pIO->end == pLoader->last)) {
        pLoader->last -= 2 * pIO->stride;
        pIO->stride = 0 - pIO->stride;
    }
    return input[pLoader->last];
}

struct VerticalDWTBandIO {
    bool CHECKED;
    int end;
    int strideHighToLow;
    int strideLowToHigh;
};

__device__ int initialize_BandIO(VerticalDWTBandIO *bandIO, const int imageSizeX, const int imageSizeY, int firstX, int firstY) {
    int columnOffset = firstX / 2;
    int verticalStride;

    if (firstX & 1) {
        verticalStride = imageSizeX / 2;
        columnOffset = columnOffset + (divRndUp(imageSizeX, 2) * divRndUp(imageSizeY, 2));
        bandIO->strideLowToHigh = (imageSizeX * imageSizeY) / 2;
    } else {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        bandIO->strideLowToHigh = divRndUp(imageSizeY, 2) * imageSizeX;
    }

    bandIO->strideHighToLow = verticalStride - bandIO->strideLowToHigh;

    if (bandIO->CHECKED) {
        bandIO->end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * bandIO->strideLowToHigh;
    } else {
        bandIO->end = 0;
    }

    return columnOffset + (firstY / 2) * verticalStride + (firstY & 1) * bandIO->strideLowToHigh;
}

