    int gx = (sx / WIN_SX) + ((sx % WIN_SX) ? 1 : 0);
    int gy = (sy / (WIN_SY * steps)) + ((sy % (WIN_SY * steps)) ? 1 : 0);

    printf("sliding steps = %d , gx = %d , gy = %d \n", steps, gx, gy);

    size_t globalWorkSize[2] = {gx * WIN_SX, gy * 1};
    size_t localWorkSize[2] = {WIN_SX, 1};

    dim3 block(localWorkSize[0], localWorkSize[1]);
    dim3 grid(globalWorkSize[0] / localWorkSize[0], globalWorkSize[1] / localWorkSize[1]);

    int *d_in = (int *)in;
    int *d_out = (int *)out;

    dwt_cuda::cl_fdwt53Kernel(d_in, d_out, sx, sy, steps, WIN_SX, WIN_SY);
    cudaDeviceSynchronize();
    printf("kl_fdwt53Kernel in launchFDW53Kernel has finished\n");
}

void memCopy_cuda(cuda_mem_t dest, cuda_mem_t src, const size_t sx, const size_t sy) {
    cudaMemcpy((void *)dest, (void *)src, sx * sy * sizeof(int), cudaMemcpyDeviceToDevice);
}

void fdwt53_cuda(cuda_mem_t in, cuda_mem_t out, int sizeX, int sizeY, int levels) {
    if (960 <= sizeX) {
        launchFDWT53Kernel_cuda(192, 8, in, out, sizeX, sizeY);
    } else if (480 <= sizeX) {
        launchFDWT53Kernel_cuda(128, 8, in, out, sizeX, sizeY);
    } else {
        launchFDWT53Kernel_cuda(64, 8, in, out, sizeX, sizeY);
    }

    if (1 < levels) {
        const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 : 0);
        const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 : 0);
        memCopy_cuda(in, out, llSizeX, llSizeY);
        fdwt53_cuda(in, out, llSizeX, llSizeY, levels - 1);
    }
}

int nStage2dDWT_cuda(cuda_mem_t in, cuda_mem_t out, cuda_mem_t backup, int pixWidth, int pixHeight, int stages, bool forward) {
