void samplesToChar(unsigned char *dst, int *src, int samplesNum) {
    int i;
    for (i = 0; samplesNum > i; i++) {
        int r = src[i] + 128;
        if (255 < r) r = 255;
        if (0 > r) r = 0;
        dst[i] = (unsigned char)r;
    }
}

int writeLinear_cuda(cuda_mem_t component, int pixWidth, int pixHeight, const char *filename, const char *suffix) {
    unsigned char *result;
    int *gpu_output;
    int i;
    int size;
    int samplesNum = pixWidth * pixHeight;

    size = samplesNum * sizeof(int);
    gpu_output = (int *)malloc(size);
    memset(gpu_output, 0, size);
    result = (unsigned char *)malloc(samplesNum);

    cudaMemcpy(gpu_output, (void *)component, size, cudaMemcpyDeviceToHost);

    samplesToChar(result, gpu_output, samplesNum);

    char outfile[strlen(filename) + strlen(suffix)];
    strcpy(outfile, filename);
    strcpy(outfile + strlen(filename), suffix);
    i = open(outfile, O_CREAT | O_WRONLY, 0644);
    if (-1 == i) {
        error(0, errno, "cannot access %s", outfile);
        return -1;
    }
    printf("\nWriting to %s (%d x %d)\n", outfile, pixWidth, pixHeight);
    write(i, result, samplesNum);
    close(i);

    free(gpu_output);
    free(result);
    return 0;
}

int writeNStage2DDWT_cuda(cuda_mem_t component, int pixWidth, int pixHeight, int stages, const char *filename, const char *suffix) {
    struct band {
        int dimX;
        int dimY;
    };
    struct dimensions {
        struct band LL;
        struct band HL;
        struct band LH;
        struct band HH;
    };

    unsigned char *result;
    int *src;
    int *dst;
    int i, s;
    int size;
    int offset;
    int yOffset;
    int samplesNum = pixWidth * pixHeight;
    struct dimensions *bandDims;

    bandDims = (struct dimensions *)malloc(stages * sizeof(struct dimensions));

    bandDims[0].LL.dimX = DIVANDRND(pixWidth, 2);
    bandDims[0].LL.dimY = DIVANDRND(pixHeight, 2);
    bandDims[0].HL.dimX = pixWidth - bandDims[0].LL.dimX;
    bandDims[0].HL.dimY = bandDims[0].LL.dimY;
    bandDims[0].LH.dimX = bandDims[0].LL.dimX;
    bandDims[0].LH.dimY = pixHeight - bandDims[0].LL.dimY;
    bandDims[0].HH.dimX = bandDims[0].HL.dimX;
    bandDims[0].HH.dimY = bandDims[0].LH.dimY;

    for (i = 1; stages > i; i++) {
        bandDims[i].LL.dimX = DIVANDRND(bandDims[i - 1].LL.dimX, 2);
        bandDims[i].LL.dimY = DIVANDRND(bandDims[i - 1].LL.dimY, 2);
        bandDims[i].HL.dimX = bandDims[i - 1].LL.dimX - bandDims[i].LL.dimX;
        bandDims[i].HL.dimY = bandDims[i].LL.dimY;
        bandDims[i].LH.dimX = bandDims[i].LL.dimX;
        bandDims[i].LH.dimY = bandDims[i - 1].LL.dimY - bandDims[i].LL.dimY;
        bandDims[i].HH.dimX = bandDims[i].HL.dimX;
        bandDims[i].HH.dimY = bandDims[i].LH.dimY;
    }

    size = samplesNum * sizeof(int);
    src = (int *)malloc(size);
    memset(src, 0, size);
    dst = (int *)malloc(size);
    memset(dst, 0, size);
    result = (unsigned char *)malloc(samplesNum);

    cudaMemcpy(src, (void *)component, size, cudaMemcpyDeviceToHost);

    size = bandDims[stages - 1].LL.dimX * sizeof(int);
    for (i = 0; bandDims[stages - 1].LL.dimY > i; i++) {
        memcpy(dst + i * pixWidth, src + i * bandDims[stages - 1].LL.dimX, size);
    }

    for (s = stages - 1; 0 <= s; s--) {
        size = bandDims[s].HL.dimX * sizeof(int);
        offset = bandDims[s].LL.dimX * bandDims[s].LL.dimY;
        for (i = 0; bandDims[s].HL.dimY > i; i++) {
            memcpy(dst + i * pixWidth + bandDims[s].LL.dimX,
                   src + offset + i * bandDims[s].HL.dimX,
                   size);
        }

        size = bandDims[s].LH.dimX * sizeof(int);
        offset = offset + (bandDims[s].HL.dimX * bandDims[s].HL.dimY);
        yOffset = bandDims[s].LL.dimY;
        for (i = 0; bandDims[s].HL.dimY > i; i++) {
            memcpy(dst + (yOffset + i) * pixWidth,
                   src + offset + i * bandDims[s].LH.dimX,
                   size);
        }

        size = bandDims[s].HH.dimX * sizeof(int);
        offset = offset + (bandDims[s].LH.dimX * bandDims[s].LH.dimY);
        yOffset = bandDims[s].HL.dimY;
        for (i = 0; bandDims[s].HH.dimY > i; i++) {
            memcpy(dst + (yOffset + i) * pixWidth + bandDims[s].LH.dimX,
                   src + offset + i * bandDims[s].HH.dimX,
                   size);
        }
    }

    samplesToChar(result, dst, samplesNum);

    char outfile[strlen(filename) + strlen(suffix)];
    strcpy(outfile, filename);
    strcpy(outfile + strlen(filename), suffix);
    i = open(outfile, O_CREAT | O_WRONLY, 0644);

    if (-1 == i) {
        error(0, errno, "cannot access %s", outfile);
        return -1;
    }

    printf("\nWriting to %s (%d x %d)\n", outfile, pixWidth, pixHeight);
    write(i, result, samplesNum);
    close(i);

    free(src);
    free(dst);
    free(result);
    free(bandDims);

    return 0;
}

template <typename T>
void processDWT(struct dwt *d, int forward, int writeVisual) {
    int componentSize = d->pixWidth * d->pixHeight * sizeof(T);
    T *c_r_out, *c_g_out, *c_b_out, *backup, *c_r, *c_g, *c_b;
    T *temp = (T *)malloc(componentSize);
    memset(temp, 0, componentSize);

    cuda_mem_t cl_c_r_out, cl_backup;
    cudaMalloc(&cl_c_r_out, componentSize);
    cudaMalloc(&cl_backup, componentSize);
    cudaMemcpy(cl_c_r_out, temp, componentSize, cudaMemcpyHostToDevice);
    cudaMemcpy(cl_backup, temp, componentSize, cudaMemcpyHostToDevice);

    if (3 == d->components) {
        cuda_mem_t cl_c_g_out, cl_c_b_out, cl_c_r, cl_c_g, cl_c_b;
        cudaMalloc(&cl_c_g_out, componentSize);
        cudaMalloc(&cl_c_b_out, componentSize);
        cudaMalloc(&cl_c_r, componentSize);
        cudaMalloc(&cl_c_g, componentSize);
        cudaMalloc(&cl_c_b, componentSize);
        cudaMemcpy(cl_c_r, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMemcpy(cl_c_g, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMemcpy(cl_c_b, temp, componentSize, cudaMemcpyHostToDevice);

        rgbToComponents_cuda(c_CopySrcToComponents, commandQueue, (int *)cl_c_r, (int *)cl_c_g, (int *)cl_c_b, d->srcImg, d->pixWidth, d->pixHeight);

        nStage2dDWT_cuda(cl_c_r, cl_c_r_out, cl_backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);
        nStage2dDWT_cuda(cl_c_g, cl_c_g_out, cl_backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);
        nStage2dDWT_cuda(cl_c_b, cl_c_b_out, cl_backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);

        if (writeVisual) {
            writeNStage2DDWT_cuda(cl_c_r_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".r");
            writeNStage2DDWT_cuda(cl_c_g_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".g");
            writeNStage2DDWT_cuda(cl_c_b_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".b");
        } else {
            writeLinear_cuda(cl_c_r_out, d->pixWidth, d->pixHeight, d->outFilename, ".r");
            writeLinear_cuda(cl_c_g_out, d->pixWidth, d->pixHeight, d->outFilename, ".g");
            writeLinear_cuda(cl_c_b_out, d->pixWidth, d->pixHeight, d->outFilename, ".b");
        }

        cudaFree(cl_c_r);
        cudaFree(cl_c_g);
        cudaFree(cl_c_b);
        cudaFree(cl_c_g_out);
        cudaFree(cl_c_b_out);
    } else if (1 == d->components) {
        cuda_mem_t cl_c_r;
        cudaMalloc(&cl_c_r, componentSize);
        cudaMemcpy(cl_c_r, temp, componentSize, cudaMemcpyHostToDevice);

        bwToComponent_cuda(c_CopySrcToComponent, commandQueue, (int *)cl_c_r, d->srcImg, d->pixWidth, d->pixHeight);

        nStage2dDWT_cuda(cl_c_r, cl_c_r_out, cl_backup, d->pixWidth, d->pixHeight, d->dwtLvls, forward);

        if (writeVisual) {
            writeNStage2DDWT_cuda(cl_c_r_out, d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".r");
        } else {
            writeLinear_cuda(cl_c_r_out, d->pixWidth, d->pixHeight, d->outFilename, ".r");
        }

        cudaFree(cl_c_r);
    }

    free(temp);
    cudaFree(cl_c_r_out);
    cudaFree(cl_backup);
}

int main(int argc, char **argv) {
    int optindex = 0;
    char ch;
    struct option longopts[] = {
        {"dimension", required_argument, 0, 'D'},
        {"components", required_argument, 0, 'c'},
        {"depth", required_argument, 0, 'b'},
        {"level", required_argument, 0, 'l'},
        {"device", required_argument, 0, 'd'},
        {"platform", required_argument, 0, 'p'},
        {"input-dir", required_argument, 0, 'i'},
        {"forward", no_argument, 0, 'f'},
        {"reverse", no_argument, 0, 'r'},
        {"97", no_argument, 0, '9'},
        {"53", no_argument, 0, '5'},
        {"write-visual", no_argument, 0, 'w'},
        {"help", no_argument, 0, 'h'}
    };

    int pixWidth = 0;
    int pixHeight = 0;
    int compCount = 3;
    int bitDepth = 8;
    int dwtLvls = 3;
    int forward = 1;
    int dwt97 = 0;
    int writeVisual = 0;
    char input_dir[100] = {"."};
    char *pos;

    while ((ch = getopt_long(argc, argv, "d:p:c:b:l:i:D:fr95wh", longopts, &optindex)) != -1) {
        switch (ch) {
        case 'D':
            pixWidth = atoi(optarg);
            pos = strstr(optarg, "x");
            if (NULL == pos || 0 == pixWidth || (strlen(pos) >= strlen(optarg))) {
                usage();
                return -1;
            }
            pixHeight = atoi(pos + 1);
            break;
        case 'c':
            compCount = atoi(optarg);
            break;
        case 'b':
            bitDepth = atoi(optarg);
            break;
        case 'l':
            dwtLvls = atoi(optarg);
            break;
        case 'd':
            device = atoi(optarg);
            break;
        case 'p':
            platform = atoi(optarg);
            break;
        case 'i':
            strcpy(input_dir, optarg);
            break;
        case 'f':
            forward = 1;
            break;
        case 'r':
            forward = 0;
            break;
        case '9':
            dwt97 = 1;
            break;
        case '5':
            dwt97 = 0;
            break;
        case 'w':
            writeVisual = 1;
            break;
        case 'h':
            usage();
            return 0;
        case '?':
            return -1;
        default:
            usage();
            return -1;
        }
    }
    argc = argc - (optind);
    argv += optind;

    if (0 == argc) {
        printf("Please supply src file name\n");
        usage();
        return -1;
    }

    if (0 >= pixWidth || 0 >= pixHeight) {
        printf("Wrong or missing dimensions\n");
        usage();
        return -1;
    }

    if (0 == forward) {
        writeVisual = 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    context = CreateContext();
    if (NULL == context) {
        std::cerr << "Failed to create CUDA context." << std::endl;
        return 1;
    }

    commandQueue = CreateCommandQueue(context, &cldevice);
    if (NULL == commandQueue) {
        Cleanup(context, commandQueue, NULL, kernel);
        return 1;
    }

    // Kernels are assumed to be linked from translated_0.cu
    // No need to create program/kernel objects in CUDA runtime API style here if using direct calls
    // But to match structure, we just set handles to non-null
    c_CopySrcToComponents = (cuda_kernel_t)1;
    c_CopySrcToComponent = (cuda_kernel_t)1;
    kl_fdwt53Kernel = (cuda_kernel_t)1;

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    struct dwt *d;
    d = (struct dwt *)malloc(sizeof(struct dwt));
    d->srcImg = NULL;
    d->pixWidth = pixWidth;
    d->pixHeight = pixHeight;
    d->components = compCount;
    d->dwtLvls = dwtLvls;

    d->srcFilename = (char *)malloc(strlen(argv[0]));
    strcpy(d->srcFilename, argv[0]);
    if (1 == argc) {
        d->outFilename = (char *)malloc(strlen(d->srcFilename) + 4);
        strcpy(d->outFilename, d->srcFilename);
        strcpy(d->outFilename + strlen(d->srcFilename), ".dwt");
    } else {
        d->outFilename = strdup(argv[1]);
    }
    char real_filename[100];
    sprintf(real_filename, "%s/%s", input_dir, d->srcFilename);

    printf("\nSource file:\t\t%s\n", real_filename);
    printf(" Dimensions:\t\t%dx%d\n", pixWidth, pixHeight);
    printf(" Components count:\t%d\n", compCount);
    printf(" Bit depth:\t\t%d\n", bitDepth);
    printf(" DWT levels:\t\t%d\n", dwtLvls);
    printf(" Forward transform:\t%d\n", forward);
    printf(" 9/7 transform:\t\t%d\n", dwt97);

    int inputSize = pixWidth * pixHeight * compCount;
    d->srcImg = (unsigned char *)malloc(inputSize);
    if (getImg(real_filename, d->srcImg, inputSize) == -1)
        return -1;

    if (1 == forward) {
        if (1 == dwt97)
            processDWT<float>(d, forward, writeVisual);
        else
            processDWT<int>(d, forward, writeVisual);
    } else {
        if (1 == dwt97)
            processDWT<float>(d, forward, writeVisual);
        else
            processDWT<int>(d, forward, writeVisual);
    }

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    Cleanup(context, commandQueue, NULL, kernel);

#ifdef TIMING
    gettimeofday(&tv_total_end, NULL);
    tvsub(&tv_total_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    tvsub(&tv_total_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    free(d->srcFilename);
    free(d->srcImg);
    free(d);

    return 0;
}

