void ForwardSub(float *a, float *b, float *m, int size, int timing) {
    float *a_dev, *b_dev, *m_dev;
    size_t mem_size_a = sizeof(float) * size * size;
    size_t mem_size_b = sizeof(float) * size;
    size_t mem_size_m = sizeof(float) * size * size;
    float writeMB = 0, readMB = 0;

    // Allocate device memory
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    CUDA_ERR_CHECK(cudaMalloc((void **)&a_dev, mem_size_a));
    CUDA_ERR_CHECK(cudaMalloc((void **)&b_dev, mem_size_b));
    CUDA_ERR_CHECK(cudaMalloc((void **)&m_dev, mem_size_m));
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy input data to device
#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    CUDA_ERR_CHECK(cudaMemcpy(a_dev, a, mem_size_a, cudaMemcpyHostToDevice));
    CUDA_ERR_CHECK(cudaMemcpy(b_dev, b, mem_size_b, cudaMemcpyHostToDevice));
    CUDA_ERR_CHECK(cudaMemcpy(m_dev, m, mem_size_m, cudaMemcpyHostToDevice));
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

    // Define block and grid sizes
    dim3 block1(BLOCK_SIZE_0, 1, 1);
    dim3 block2(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y, 1);

    // Grid size calculation (ceil division)
    int grid1_x = (size + block1.x - 1) / block1.x;
    int grid2_x = (size + block2.x - 1) / block2.x;
    int grid2_y = (size + block2.y - 1) / block2.y;

    dim3 grid1(grid1_x, 1, 1);
    dim3 grid2(grid2_x, grid2_y, 1);

    int t;

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    for (t = 0; t < (size - 1); t++) {
        // Launch Fan1
        Fan1_cuda<<<grid1, block1>>>(m_dev, a_dev, b_dev, size, t);
        CUDA_ERR_CHECK(cudaGetLastError());

        // Launch Fan2
        Fan2_cuda<<<grid2, block2>>>(m_dev, a_dev, b_dev, size, t);
        CUDA_ERR_CHECK(cudaGetLastError());

        // Ensure completion before next iteration (since data dependencies exist between iterations)
        CUDA_ERR_CHECK(cudaDeviceSynchronize());
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy results back to host
#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    CUDA_ERR_CHECK(cudaMemcpy(a, a_dev, mem_size_a, cudaMemcpyDeviceToHost));
    CUDA_ERR_CHECK(cudaMemcpy(b, b_dev, mem_size_b, cudaMemcpyDeviceToHost));
    CUDA_ERR_CHECK(cudaMemcpy(m, m_dev, mem_size_m, cudaMemcpyDeviceToHost));
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    readMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

#ifdef TIMING
    printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
    printf("%dx%d      \t",size,size);
    printf("%f [%.2fMB]\t",h2d_time,writeMB);
    printf("%f\t",kernel_time);
    printf("%f [%.2fMB]\t",d2h_time,readMB);
    printf("%f\n\n",h2d_time+kernel_time+d2h_time);
#endif

    // Free device memory
#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
}

// Helper for timeval subtraction
void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *res) {
    res->tv_sec = t1->tv_sec - t2->tv_sec;
    res->tv_usec = t1->tv_usec - t2->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}

