extern int platform_id_inuse;
extern int device_id_inuse;

void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *diff) {
    diff->tv_sec = t1->tv_sec - t0->tv_sec;
    diff->tv_usec = t1->tv_usec - t0->tv_usec;
    if (diff->tv_usec < 0) {
        diff->tv_sec--;
        diff->tv_usec += 1000000;
    }
}

void fatal(const char *s) {
    fprintf(stderr, "Error: %s\n", s);
    exit(1);
}

