void fatal_cuda(cudaError_t error, int line_no) {
    if (error != cudaSuccess) {
        fprintf(stderr, "CUDA Error at line %d: %s\n", line_no, cudaGetErrorString(error));
        exit(1);
    }
}

void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *res) {
    res->tv_sec = t1->tv_sec - t0->tv_sec;
    res->tv_usec = t1->tv_usec - t0->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}

