                        float *power,
                        float *temp_src,
                        float *temp_dst,
                        int grid_cols,
                        int grid_rows,
                        int border_cols,
                        int border_rows,
                        float Cap,
                        float Rx,
                        float Ry,
                        float Rz,
                        float step) {

