#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <assert.h>
#include <cuda_runtime.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define STR_SIZE 256
#define EXPAND_RATE 2
#define MAX_PD (3.0e6)
#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP 0.5

#define MIN(a, b) ((a) <= (b) ? (a) : (b))

const static float t_chip = 0.0005;
const static float chip_height = 0.016;
const static float chip_width = 0.016;
const static float amb_temp = 80.0;

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))

void fatal(const char *s) {
    fprintf(stderr, "Error: %s\n", s);
    exit(1);
}

void check_cuda_error(cudaError_t err, int line_no) {
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA Error at line %d: %s\n", line_no, cudaGetErrorString(err));
        exit(err);
    }
}

__global__ void hotspot(int iteration,
                        const float *power,
                        const float *temp_src,
                        float *temp_dst,
                        int grid_cols,
                        int grid_rows,
                        int border_cols,
                        int border_rows,
                        float Cap,
                        float Rx,
                        float Ry,
                        float Rz,
                        float step) {

    float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    float step_div_Cap;
    float Rx_1, Ry_1, Rz_1;

    int bx = blockIdx.x;
    int by = blockIdx.y;

    int tx = threadIdx.x;
    int ty = threadIdx.y;

    step_div_Cap = step / Cap;

    Rx_1 = 1.0f / Rx;
    Ry_1 = 1.0f / Ry;
    Rz_1 = 1.0f / Rz;

    int small_block_rows = BLOCK_SIZE - iteration * 2;
    int small_block_cols = BLOCK_SIZE - iteration * 2;

    int blkY = small_block_rows * by - border_rows;
    int blkX = small_block_cols * bx - border_cols;
    int blkYmax = blkY + BLOCK_SIZE - 1;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int yidx = blkY + ty;
    int xidx = blkX + tx;

    int loadYidx = yidx, loadXidx = xidx;
    int index = grid_cols * loadYidx + loadXidx;

    if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
        temp_on_cuda[ty][tx] = temp_src[index];
        power_on_cuda[ty][tx] = power[index];
    } else {
        temp_on_cuda[ty][tx] = 0.0f;
        power_on_cuda[ty][tx] = 0.0f;
    }
    __syncthreads();

    int validYmin = (blkY < 0) ? -blkY : 0;
    int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
    int validXmin = (0 > blkX) ? -blkX : 0;
    int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (N < validYmin) ? validYmin : N;
    S = (validYmax < S) ? validYmax : S;
    W = (W < validXmin) ? validXmin : W;
    E = (validXmax < E) ? validXmax : E;

    bool computed = false;
    for (int i = 0; i < iteration; i++) {
        computed = false;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, validXmin, validXmax) &&
            IN_RANGE(ty, validYmin, validYmax)) {
            computed = true;
            temp_t[ty][tx] = temp_on_cuda[ty][tx] + step_div_Cap * (power_on_cuda[ty][tx] +
                    (temp_on_cuda[S][tx] + temp_on_cuda[N][tx] - 2.0f * temp_on_cuda[ty][tx]) * Ry_1 +
                    (temp_on_cuda[ty][E] + temp_on_cuda[ty][W] - 2.0f * temp_on_cuda[ty][tx]) * Rx_1 +
                    (amb_temp - temp_on_cuda[ty][tx]) * Rz_1);
        }
        __syncthreads();

        if (iteration - 1 == i)
            break;
        if (computed)
            temp_on_cuda[ty][tx] = temp_t[ty][tx];

        __syncthreads();
    }

    if (computed) {
        if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
            temp_dst[index] = temp_t[ty][tx];
        }
    }
}

void writeoutput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++) {
            sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            fputs(str, fp);
            index++;
        }

    fclose(fp);
}

void readinput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if ((fp = fopen(file, "r")) == 0)
        fatal("The file was not opened");

    for (i = 0; i <= grid_rows - 1; i++)
        for (j = 0; j <= grid_cols - 1; j++) {
            if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (feof(fp))
                fatal("not enough lines in file");

            if ((sscanf(str, "%f", &val) != 1))
                fatal("invalid file format");
            vect[i * grid_cols + j] = val;
        }

    fclose(fp);
}

// Revised compute function for CUDA that handles everything
int run_hotspot_cuda(float *power_host, float *temp_host, int grid_cols, int grid_rows, 
                     int total_iterations, int pyramid_height, 
                     int blockCols, int blockRows, int borderCols, int borderRows) {

    float grid_height = chip_height / grid_rows;
    float grid_width = chip_width / grid_cols;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    float Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
    float Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
    float Rz = t_chip / (K_SI * grid_height * grid_width);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float step = PRECISION / max_slope;

    int num_iterations = pyramid_height;
    int size = grid_rows * grid_cols;

    float *d_power;
    float *d_temp[2];
    size_t mem_size = size * sizeof(float);

    check_cuda_error(cudaMalloc(&d_power, mem_size), __LINE__);
    check_cuda_error(cudaMalloc(&d_temp[0], mem_size), __LINE__);
    check_cuda_error(cudaMalloc(&d_temp[1], mem_size), __LINE__);

    check_cuda_error(cudaMemcpy(d_power, power_host, mem_size, cudaMemcpyHostToDevice), __LINE__);
    check_cuda_error(cudaMemcpy(d_temp[0], temp_host, mem_size, cudaMemcpyHostToDevice), __LINE__);

    dim3 global_work_size(BLOCK_SIZE * blockCols, BLOCK_SIZE * blockRows);
    dim3 local_work_size(BLOCK_SIZE, BLOCK_SIZE);

    int src = 0;
    int t;

    for (t = 0; t < total_iterations; t += num_iterations) {
        int iter = MIN(num_iterations, total_iterations - t);
        int current_src = src;
        int current_dst = 1 - src;

        hotspot<<<global_work_size, local_work_size>>>(iter, d_power, d_temp[current_src], d_temp[current_dst],
                grid_cols, grid_rows, borderCols, borderRows, Cap, Rx, Ry, Rz, step);

        check_cuda_error(cudaDeviceSynchronize(), __LINE__);

        src = 1 - src;
    }

    // Result is in d_temp[src]
    check_cuda_error(cudaMemcpy(temp_host, d_temp[src], mem_size, cudaMemcpyDeviceToHost), __LINE__);

    cudaFree(d_power);
    cudaFree(d_temp[0]);
    cudaFree(d_temp[1]);

    return 0;
}

