__global__ void hotspot(  int iteration,  
                               float *power,   
                               float *temp_src,    
                               float *temp_dst,    
                               int grid_cols,  
                               int grid_rows,  
							   int border_cols,  
							   int border_rows,  
                               float Cap,      
                               float Rx, 
                               float Ry, 
                               float Rz, 
                               float step) {

	__shared__ float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
	__shared__ float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
	__shared__ float temp_t[BLOCK_SIZE][BLOCK_SIZE]; 

	float amb_temp_local = 80.0f;
	float step_div_Cap;
	float Rx_1,Ry_1,Rz_1;

	int bx = blockIdx.x;
	int by = blockIdx.y;

	int tx = threadIdx.x;
	int ty = threadIdx.y;

	step_div_Cap=step/Cap;

	Rx_1=1/Rx;
	Ry_1=1/Ry;
	Rz_1=1/Rz;

	int small_block_rows = BLOCK_SIZE-iteration*2;
	int small_block_cols = BLOCK_SIZE-iteration*2;

	int blkY = small_block_rows*by-border_rows;
	int blkX = small_block_cols*bx-border_cols;
	int blkYmax = blkY+BLOCK_SIZE-1;
	int blkXmax = blkX+BLOCK_SIZE-1;

	int yidx = blkY+ty;
	int xidx = blkX+tx;

	int loadYidx=yidx, loadXidx=xidx;
	int index = grid_cols*loadYidx+loadXidx;

	if(IN_RANGE(loadYidx, 0, grid_rows-1) && IN_RANGE(loadXidx, 0, grid_cols-1)){
            temp_on_cuda[ty][tx] = temp_src[index];  
            power_on_cuda[ty][tx] = power[index];
	}
	__syncthreads();

	int validYmin = (0 > blkY) ? -blkY : 0;
	int validYmax = (blkYmax > grid_rows-1) ? BLOCK_SIZE-1-(blkYmax-grid_rows+1) : BLOCK_SIZE-1;
	int validXmin = (0 > blkX) ? -blkX : 0;
	int validXmax = (blkXmax > grid_cols-1) ? BLOCK_SIZE-1-(blkXmax-grid_cols+1) : BLOCK_SIZE-1;

	int N = ty-1;
	int S = ty+1;
	int W = tx-1;
	int E = tx+1;

	N = (validYmin > N) ? validYmin : N;
	S = (validYmax < S) ? validYmax : S;
	W = (validXmin > W) ? validXmin : W;
	E = (validXmax < E) ? validXmax : E;

	bool computed;
	for (int i=0; iteration > i ; i++){ 
		computed = false;
		if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) &&  \
		IN_RANGE(ty, i+1, BLOCK_SIZE-i-2) &&  \
		IN_RANGE(tx, validXmin, validXmax) && \
		IN_RANGE(ty, validYmin, validYmax) ) {
			computed = true;
			temp_t[ty][tx] =   temp_on_cuda[ty][tx] + step_div_Cap * (power_on_cuda[ty][tx] + 
			(temp_on_cuda[S][tx] + temp_on_cuda[N][tx] - 2.0f * temp_on_cuda[ty][tx]) * Ry_1 + 
			(temp_on_cuda[ty][E] + temp_on_cuda[ty][W] - 2.0f * temp_on_cuda[ty][tx]) * Rx_1 + 
			(amb_temp_local - temp_on_cuda[ty][tx]) * Rz_1);

		}
		__syncthreads();

		if(iteration-1 == i)
			break;
		if(computed)	 
			temp_on_cuda[ty][tx]= temp_t[ty][tx];

		__syncthreads();
	}

	if (computed){
	  temp_dst[index]= temp_t[ty][tx];		
	}
