// Helper function for time subtraction (inline definition to avoid header dependency)
void tvsub(struct timeval *tout, struct timeval *tin, struct timeval *tout_sub) {
    tout_sub->tv_sec = tout->tv_sec - tin->tv_sec;
    tout_sub->tv_usec = tout->tv_usec - tin->tv_usec;
    if (tout_sub->tv_usec < 0) {
        tout_sub->tv_sec--;
        tout_sub->tv_usec += 1000000;
    }
}

