		float4 nextB = input[Bstart + bidx + 1];

		float4 na = getLowest(a,b);
		float4 nb = getHighest(a,b);
		a = sortElem(na);
		b = sortElem(nb);

		resStart[outidx++] = a;

		bool elemsLeftInA;
		bool elemsLeftInB;

		elemsLeftInA = (aidx + 1 < nrElems/2); 
		elemsLeftInB = (bidx + 1 < nrElems/2) && (Bstart + bidx + 1 < constStartAddr[division + 1]);

		if(elemsLeftInA){
