	int		index =0;						
	int		rmse;							
    int    *membership;						
    float **tmp_cluster_centres;			
	int		i;


    membership = (int*) malloc(npoints * sizeof(int));


	for(nclusters = min_nclusters; max_nclusters >= nclusters; nclusters++)
	{
		if (npoints < nclusters) break;	


		allocate(npoints, nfeatures, nclusters, features);


		for(i = 0; nloops > i; i++)
		{

			tmp_cluster_centres = kmeans_clustering(features,
													nfeatures,
													npoints,
													nclusters,
													threshold,
													membership);

			if (*cluster_centres) {
				free((*cluster_centres)[0]);
				free(*cluster_centres);
			}
			*cluster_centres = tmp_cluster_centres;



			if(isRMSE)
			{
				rmse = rms_err(features,
							   nfeatures,
							   npoints,
							   tmp_cluster_centres,
							   nclusters);

				if(min_rmse_ref > rmse){
					min_rmse_ref = rmse;			
					*min_rmse = min_rmse_ref;		
					*best_nclusters = nclusters;	
					index = i;						
				}
			}			
		}

		deallocateMemory();							
	}

