typedef enum _FUNC_RETURN_CODE {
    RET_SUCCESS,
    RET_FAILURE
} func_ret_t;

typedef struct __stopwatch_t{
    struct timeval begin;
    struct timeval end;
} stopwatch;

#define GET_RAND_FP ( (float)rand() / ((float)(RAND_MAX)+(float)(1)) )
#define MIN(i,j) ((i)<(j) ? (i) : (j))

void stopwatch_start(stopwatch *sw){
    if (sw == NULL) return;
    bzero(&sw->begin, sizeof(struct timeval));
    bzero(&sw->end  , sizeof(struct timeval));
    gettimeofday(&sw->begin, NULL);
}

void stopwatch_stop(stopwatch *sw){
    if (sw == NULL) return;
    gettimeofday(&sw->end, NULL);
}

double get_interval_by_sec(stopwatch *sw){
    if (sw == NULL) return 0;
    return ((double)(sw->end.tv_sec-sw->begin.tv_sec)+(double)(sw->end.tv_usec-sw->begin.tv_usec)/1000000);
}

int get_interval_by_usec(stopwatch *sw){
    if (sw == NULL) return 0;
    return ((sw->end.tv_sec-sw->begin.tv_sec)*1000000+(sw->end.tv_usec-sw->begin.tv_usec));
}

func_ret_t create_matrix_from_file(float **mp, const char* filename, size_t *size_p){
    int i, j, size;
    float *m;
    FILE *fp = NULL;

    fp = fopen(filename, "rb");
    if ( fp == NULL) {
        return RET_FAILURE;
    }

    fscanf(fp, "%d\n", &size);

    m = (float*) malloc(sizeof(float)*size*size);
    if ( m == NULL) {
        fclose(fp);
        return RET_FAILURE;
    }

    for (i=0; i < size; i++) {
        for (j=0; j < size; j++) {
            fscanf(fp, "%f ", m+i*size+j);
        }
    }

    fclose(fp);

    *size_p = size;
    *mp = m;

    return RET_SUCCESS;
}

func_ret_t create_matrix_from_random(float **mp, int size){
    float *l, *u, *m;
    int i,j,k;

    srand(time(NULL));

    l = (float*)malloc(size*size*sizeof(float));
    if ( l == NULL)
        return RET_FAILURE;

    u = (float*)malloc(size*size*sizeof(float));
    if ( u == NULL) {
        free(l);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j=0; j < size; j++) {
            if (i>j) {
                l[i*size+j] = GET_RAND_FP;
            } else if (i == j) {
                l[i*size+j] = 1;
            } else {
                l[i*size+j] = 0;
            }
        }
    }

    for (j=0; j < size; j++) {
        for (i=0; i < size; i++) {
            if (i>j) {
                u[j*size+i] = 0;
            }else {
                u[j*size+i] = GET_RAND_FP; 
            }
        }
    }

    m = (float*)malloc(size*size*sizeof(float));
    for (i=0; i < size; i++) {
        for (j=0; j < size; j++) {
            float sum = 0.0f;
            for (k=0; k <= MIN(i,j); k++)
                sum += l[i*size+k] * u[j*size+k];
            m[i*size+j] = sum;
        }
    }

    free(l);
    free(u);

    *mp = m;

    return RET_SUCCESS;
}

void matrix_multiply(float *inputa, float *inputb, float *output, int size){
    int i, j, k;
    for (i=0; i < size; i++) {
        for (j=0; j < size; j++) {
            float sum = 0.0f;
            for (k=0; k < size; k++)
                sum += inputa[i*size+k] * inputb[k*size+j];
            output[i*size+j] = sum;
        }
    }
}

func_ret_t lud_verify(float *m, float *lu, int matrix_dim){
    int i,j,k;
    float *tmp = (float*)malloc(matrix_dim*matrix_dim*sizeof(float));
    if (!tmp) return RET_FAILURE;

    for (i=0; i < matrix_dim; i ++)
        for (j=0; j< matrix_dim; j++) {
            float sum = 0;
            float l,u;
            for (k=0; k <= MIN(i,j); k++){
                if ( i==k)
                    l=1;
                else
                    l=lu[i*matrix_dim+k];
                u=lu[k*matrix_dim+j];
                sum+=l*u;
            }
            tmp[i*matrix_dim+j] = sum;
        }

    int mismatch = 0;
    for (i=0; i<matrix_dim; i++){
        for (j=0; j<matrix_dim; j++){
            if ( fabs(m[i*matrix_dim+j]-tmp[i*matrix_dim+j]) > 0.0001) {
                printf("dismatch at (%d, %d): (o)%f (n)%f\n", i, j, m[i*matrix_dim+j], tmp[i*matrix_dim+j]);
                mismatch = 1;
            }
        }
    }
    free(tmp);
    return mismatch ? RET_FAILURE : RET_SUCCESS;
}

void matrix_duplicate(float *src, float **dst, int matrix_dim) {
    int s = matrix_dim*matrix_dim*sizeof(float);
    float *p = (float *) malloc (s);
    memcpy(p, src, s);
    *dst = p;
}

