}

func_ret_t create_matrix(float **mp, int size){
    float *m;
    int i,j;
    float lamda = -0.001;
    float coe[2*size-1];
    float coe_i =0.0;

    for (i=0; i < size; i++)
    {
        coe_i = 10*exp(lamda*i); 
        j=size-1+i;     
        coe[j]=coe_i;
        j=size-1-i;     
        coe[j]=coe_i;
    }

    m = (float*) malloc(sizeof(float)*size*size);
    if ( m == NULL) {
        return RET_FAILURE;
    }

    for (i=0; i < size; i++) {
        for (j=0; j < size; j++) {
            m[i*size+j]=coe[size-1-i+j];
        }
    }

    *mp = m;

    return RET_SUCCESS;
}

__global__ void 
lud_diagonal(float *m, 
             float *shadow,
             int   matrix_dim, 
             int   offset)
{ 
    int i,j;
