int 
kernel_gpu_opencl_wrapper(	int xmax,
							int workload,

							fp ***y,
							fp **x,
							fp **params,
							fp *com)
{


	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long timecopyin = 0;
	long long timekernel = 0;
	long long timecopyout = 0;
	long long timeother;


	int i;


	fp* d_initvalu;
	fp* d_finavalu;
	fp* d_params;
	fp* d_com;

	int d_initvalu_mem = EQUATIONS * sizeof(fp);
	int d_finavalu_mem = EQUATIONS * sizeof(fp);
	int d_params_mem = PARAMETERS * sizeof(fp);
	int d_com_mem = 3 * sizeof(fp);

	d_initvalu = (fp*)malloc(d_initvalu_mem);
	d_finavalu = (fp*)malloc(d_finavalu_mem);
	d_params = (fp*)malloc(d_params_mem);
	d_com = (fp*)malloc(d_com_mem);

	time0 = 0; 
	time1 = 0;

	for(i=0; i<workload; i++){

		int status = solver(	y[i],
							x[i],
							xmax,
							params[i],
							com,

							d_initvalu,
							d_finavalu,
							d_params,
							d_com);

		if(status !=0){
			printf("STATUS: %d\n", status);
		}

	}

	time3 = 0;


	free(d_initvalu);
	free(d_finavalu);
	free(d_params);
	free(d_com);

	time4= 0;


	printf("Time spent in different stages of the application:\n");
	printf("%15.12f s, %15.12f % : CPU: GPU SETUP\n", 								(float) (time1-time0) / 1000000, 0.0);
	printf("%15.12f s, %15.12f % : CPU: ALLOCATE GPU MEMORY\n", 					(float) (time2-time1) / 1000000, 0.0);
	printf("%15.12f s, %15.12f % : GPU: COMPUTATION\n", 							(float) (time3-time2) / 1000000, 0.0);

	printf("\tGPU: COMPUTATION Components:\n");
	printf("\t%15.12f s, %15.12f % : GPU: COPY DATA IN\n", 							(float) (timecopyin) / 1000000, 0.0);
	printf("\t%15.12f s, %15.12f % : GPU: KERNEL\n", 								(float) (timekernel) / 1000000, 0.0);
	printf("\t%15.12f s, %15.12f % : GPU: COPY DATA OUT\n", 						(float) (timecopyout) / 1000000, 0.0);
	timeother = time3-time2-timecopyin-timekernel-timecopyout;
	printf("\t%15.12f s, %15.12f % : GPU: OTHER\n", 								(float) (timeother) / 1000000, 0.0);

	printf("%15.12f s, %15.12f % : CPU: FREE GPU MEMORY\n", 						(float) (time4-time3) / 1000000, 0.0);
	printf("Total time:\n");
	printf("%.12f s\n", 															(float) (time4-time0) / 1000000);


	return 0;

}

