		initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0][i] + b12_6*finavalu_temp[5][i] + b12_7*finavalu_temp[6][i] + b12_8*finavalu_temp[7][i] + b12_9*finavalu_temp[8][i] + b12_10 * finavalu_temp[9][i]) ;
	}

	master(	timeinst_temp,
					initvalu_temp,
					parameter,
					finavalu_temp[11],
					com,

					d_initvalu,
					d_finavalu,
					d_params,
					d_com);


	timeinst_temp = timeinst+h;
	for(i=0; i<EQUATIONS; i++){
		initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0][i] + b13_4*finavalu_temp[3][i] + b13_5*finavalu_temp[4][i] + b13_6*finavalu_temp[5][i] + b13_7*finavalu_temp[6][i] + b13_8*finavalu_temp[7][i] + b13_9*finavalu_temp[8][i] + b13_10*finavalu_temp[9][i] + finavalu_temp[11][i]) ;
	}

	master(	timeinst_temp,
					initvalu_temp,
					parameter,
					finavalu_temp[12],
					com,

					d_initvalu,
					d_finavalu,
					d_params,
					d_com);


	for(i=0; i<EQUATIONS; i++){
		finavalu[i]= initvalu[i] +  h * (c_1_11 * (finavalu_temp[0][i] + finavalu_temp[10][i])  + c6 * finavalu_temp[5][i] + c_7_8 * (finavalu_temp[6][i] + finavalu_temp[7][i]) + c_9_10 * (finavalu_temp[8][i] + finavalu_temp[9][i]) );
	}


	for(i=0; i<EQUATIONS; i++){
		error[i] = fabs(err_factor * (finavalu_temp[0][i] + finavalu_temp[10][i] - finavalu_temp[11][i] - finavalu_temp[12][i]));
	}


	free(initvalu_temp);
	free(finavalu_temp);

}

int 
solver(	fp **y,
		fp *x,
		int xmax,
		fp *params,
		fp *com,

		fp* d_initvalu,
		fp* d_finavalu,
		fp* d_params,
		fp* d_com)
{


	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;


	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));


	int i, j, k;


	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);


	x[0] = 0;


	if (xmin > xmax || 0.0 >= h){
		free(err); free(scale); free(yy);
		return -2;
	}


	if (xmin == xmax){
		free(err); free(scale); free(yy);
		return 0; 
	}


	if ((xmax - xmin) < h ) { 
		h = (fp)xmax - (fp)xmin; 
	}


	printf("Time Steps: ");
	fflush(stdout);

	for(k=1; xmax >= k; k++) {											

		x[k] = k-1;
		h = h_init;

		scale_fina = 1.0;

		for (j = 0; 12 > j; j++) {

			error = 0;
			outside = 0;
			scale_min = 4.0;

			embedded_fehlberg_7_8(	x[k],
									h,
									y[k-1],
									y[k],
									err,
									params,
									com,

									d_initvalu,
									d_finavalu,
									d_params,
									d_com);

			for(i=0; i<EQUATIONS; i++){
				if(0 < err[i]){
					error = 1;
				}
			}
			if (1 != error) {
				scale_fina = 4.0; 
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(0.0 == y[k-1][i]){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale_min > scale[i]){
					scale_min = scale[i];
				}
			}
			if (scale_min < 0.125) scale_min = 0.125;
			if (scale_min > 4.0) scale_min = 4.0;
			scale_fina = scale_min;

			for(i=0; i<EQUATIONS; i++){
				if ( ( tolerance * yy[i] ) < err[i] ){
					outside = 1;
				}
			}
			if (0 == outside){
				break;
			}

			h = h * scale_fina;

			if (0.9 <= h) {
				h = 0.9;
			}

			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5 * h > (fp)xmax ){
				h = 0.5 * h;
			}

		}

		x[k] = x[k] + h;

		if ( 12 <= j ) {
			free(err);
			free(scale);
			free(yy);
			return -1; 
		}

		printf("%d ", k);
		fflush(stdout);

	}

	printf("\n");
	fflush(stdout);

	free(err);
	free(scale);
	free(yy);

	return 0;

} 

int 
kernel_gpu_opencl_wrapper(	int xmax,
							int workload,

							fp ***y,
							fp **x,
							fp **params,
							fp *com)
{


	int i;


	fp* d_initvalu;
	fp* d_finavalu;
	fp* d_params;
	fp* d_com;

	cudaMalloc(&d_initvalu, EQUATIONS * sizeof(fp));
	cudaMalloc(&d_finavalu, EQUATIONS * sizeof(fp));
	cudaMalloc(&d_params, PARAMETERS * sizeof(fp));
	cudaMalloc(&d_com, 3 * sizeof(fp));

	int status;

	for(i=0; workload > i; i++){

		status = solver(	y[i],
							x[i],
							xmax,
							params[i],
							com,

							d_initvalu,
							d_finavalu,
							d_params,
							d_com);

		if(0 != status){
			printf("STATUS: %d\n", status);
		}

	}

	cudaFree(d_initvalu);
	cudaFree(d_finavalu);
	cudaFree(d_params);
	cudaFree(d_com);

	return 0;

}

