#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <vector>
#include <iostream>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

// Inline definitions from headers to avoid missing files
typedef struct {
    float lat;
    float lng;
} LatLong;

typedef struct {
    char recString[49];
    float distance;
} Record;

#define REC_LENGTH 49

// CUDA Kernel equivalent to OpenCL NearestNeighbor
__global__ void NearestNeighbor(LatLong *d_locations,
                                float *d_distances,
                                const int numRecords,
                                const float lat,
                                const float lng) {
    int globalId = threadIdx.x + blockIdx.x * blockDim.x;

    if (globalId < numRecords) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        *dist = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) +
                            (lng - latLong->lng) * (lng - latLong->lng));
    }
}

// Helper functions mimicking the OpenCL utility behavior for CUDA
void checkError(cudaError_t status, const char *msg, bool exitOnErr) {
    if (status != cudaSuccess) {
        printf("CUDA Error: %d %s %s\n", (int)status, cudaGetErrorString(status), msg);
        if (exitOnErr) {
            exit(-1);
        }
    }
}

void cuda_cleanup() {
    cudaDeviceReset();
}

void* allocBuffer(size_t mem_size, bool readOnly = false) {
    void* mem;
    cudaError_t status;
    status = cudaMalloc(&mem, mem_size);
    checkError(status, "creating buffer", true);
    return mem;
}

void copyBufferToDevice(void* dst, void* src, size_t mem_size) {
    cudaError_t status = cudaMemcpy(dst, src, mem_size, cudaMemcpyHostToDevice);
    checkError(status, "Writing buffer", true);
}

void copyBufferToHost(void* dst, void* src, size_t mem_size) {
    cudaError_t status = cudaMemcpy(dst, src, mem_size, cudaMemcpyDeviceToHost);
    checkError(status, "Reading buffer", true);
}

void freeMem(void* mem) {
    if (mem != NULL) {
        cudaFree(mem);
    }
}

double computeExecTime(cudaEvent_t event_start, cudaEvent_t event_end) {
    float elapsed;
    cudaEventElapsedTime(&elapsed, event_start, event_end);
    return (double)elapsed;
}

// Main logic translated from OpenCL to CUDA
float *CudaFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat,
    float lng,
    int timing) {

    void* d_locations;
    void* d_distances;

    cudaError_t error;

    d_locations = allocBuffer(sizeof(LatLong) * numRecords, true);
    d_distances = allocBuffer(sizeof(float) * numRecords, false);

    copyBufferToDevice(d_locations, &locations[0], sizeof(LatLong) * numRecords);

    // Setup kernel arguments via direct launch
    int blockSize = 64;
    int numBlocks = (numRecords + blockSize - 1) / blockSize;

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    if (timing) {
        cudaEventRecord(start);
    }

    NearestNeighbor<<<numBlocks, blockSize>>>( (LatLong*)d_locations, (float*)d_distances, numRecords, lat, lng);

    // Check for launch errors immediately
    cudaError_t launchErr = cudaGetLastError();
    if (launchErr != cudaSuccess) {
        printf("CUDA Launch Error: %s\n", cudaGetErrorString(launchErr));
        exit(-1);
    }

    // Ensure completion before reading or timing
    cudaError_t syncErr = cudaDeviceSynchronize();
    if (syncErr != cudaSuccess) {
        printf("CUDA Sync Error: %s\n", cudaGetErrorString(syncErr));
        exit(-1);
    }

    if (timing) {
        cudaEventRecord(stop);
        cudaEventSynchronize(stop);
    }

    float *distances = (float *)malloc(sizeof(float) * numRecords);

    copyBufferToHost(distances, d_distances, sizeof(float) * numRecords);

    if (timing) {
        double kernelTime = computeExecTime(start, stop);
        printf("Kernel execution time: %f ms\n", kernelTime);
    }

    freeMem(d_locations);
    freeMem(d_distances);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return distances;
}

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    // Use a default folder if environment variable is not set, but allow override via argument parsing if needed
    // For this translation, we assume the filelist contains relative paths or the user sets DATA_FOLDER
    char *data_folder = getenv("DATA_FOLDER");
    const char* default_folder = ".";
    char folder_buf[256];

    if (!data_folder) {
        strcpy(folder_buf, default_folder);
        data_folder = folder_buf;
    } else {
        strcpy(folder_buf, data_folder);
        data_folder = folder_buf;
    }

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist: %s\n", filename);
        exit(0);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            // Handle potential trailing newline or empty line
            if (feof(flist)) break;
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }

        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            // If the file doesn't exist, maybe the list has empty lines or the path is wrong.
            // In the original code, it exits. We'll exit too to match behavior, 
            // but ensure the path construction is correct.
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            // Initialize recString to avoid garbage
            memset(record.recString, 0, REC_LENGTH);

            if (fgets(record.recString, REC_LENGTH, fp) == NULL) break;

            // Remove newline if present
            size_t len = strlen(record.recString);
            if (len > 0 && record.recString[len-1] == '\n') {
                record.recString[len-1] = '\0';
                len--;
            }
            // Handle carriage return
            if (len > 0 && record.recString[len-1] == '\r') {
                record.recString[len-1] = '\0';
                len--;
            }

            if (len < 38) {
                // Line too short for expected format, skip or break? 
                // Original code assumes valid format. Let's try to parse safely.
                // If too short, atof will return 0 for missing parts, which is acceptable.
            }

            char substr[6];
            // Extract latitude (starts at index 28, 5 chars)
            for (i = 0; i < 5; i++) {
                if (28 + i < len) substr[i] = record.recString[28 + i];
                else substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            // Extract longitude (starts at index 33, 5 chars)
            for (i = 0; i < 5; i++) {
                if (33 + i < len) substr[i] = record.recString[33 + i];
                else substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
            case 'r':
                if (i+1 >= argc) return 1;
                i++;
                *r = atoi(argv[i]);
                break;
            case 'l':
                if (i+1 >= argc) return 1;
                if (argv[i][2] == 'a') {
                    *lat = atof(argv[i + 1]);
                } else {
                    *lng = atof(argv[i + 1]);
                }
                i++;
                break;
            case 'h':
                return 1;
                break;
            case 'q':
                *q = 1;
                break;
            case 't':
                *t = 1;
                break;
            case 'p':
                if (i+1 >= argc) return 1;
                i++;
                *p = atoi(argv[i]);
                break;
            case 'd':
                if (i+1 >= argc) return 1;
                i++;
                *d = atoi(argv[i]);
                break;
            case 'f':
                if (i+1 >= argc) return 1;
                i++;
                // In a full app, this would set a global. 
                // Here we rely on DATA_FOLDER env var or default "."
                break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
