unsigned int roundUp(unsigned int value, unsigned int multiple) {
    unsigned int remainder = value % multiple;
    if (remainder != 0) {
        value += (multiple - remainder);
    }
    return value;
}

char* smartStrcat(char* str1, char* str2) {
    char* newStr = NULL;
    newStr = (char*)alloc((strlen(str1) + strlen(str2) + 1) * sizeof(char));
    strcpy(newStr, str1);
    strcat(newStr, str2);
    return newStr;
}

// Timing helpers
void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *res) {
    res->tv_sec = t1->tv_sec - t2->tv_sec;
    res->tv_usec = t1->tv_usec - t2->tv_usec;
    if (res->tv_usec < 0) {
        res->tv_sec--;
        res->tv_usec += 1000000;
    }
}

// CUDA Initialization and Management
void cuda_init_context(int platform, int dev, int quiet) {
    // In CUDA, we don't have platforms/devices in the same sense as OpenCL.
    // We just ensure CUDA is initialized.
    int deviceCount = 0;
    cudaError_t err = cudaGetDeviceCount(&deviceCount);
    if (err != cudaSuccess || deviceCount == 0) {
        printf("No CUDA devices found\n");
        exit(-1);
    }
    if (!quiet) {
        printf("Number of CUDA devices detected: %d\n", deviceCount);
        printf("Using Device %d\n", (dev >= 0 && dev < deviceCount) ? dev : 0);
    }
    int chosen_device = (dev >= 0 && dev < deviceCount) ? dev : 0;
    cudaSetDevice(chosen_device);
}

void cuda_cleanup() {
    cudaDeviceReset();
}

cudaError_t cuda_allocBuffer(void** devPtr, size_t mem_size) {
    return cudaMalloc(devPtr, mem_size);
}

void cuda_freeBuffer(void* devPtr) {
    cudaFree(devPtr);
}

cudaError_t cuda_copyBufferToDevice(void* dst, void* src, size_t mem_size) {
    return cudaMemcpy(dst, src, mem_size, cudaMemcpyHostToDevice);
}

cudaError_t cuda_copyBufferToHost(void* dst, void* src, size_t mem_size) {
    return cudaMemcpy(dst, src, mem_size, cudaMemcpyDeviceToHost);
}

// Main logic translated from OpenClFindNearestNeighbors
float *CUDAFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat, float lng,
    int timing) {

    LatLong *d_locations = NULL;
    float *d_distances = NULL;
    cudaError_t err;

    struct timeval tv, tv_mem_alloc_start, tv_mem_alloc_end;
    float mem_alloc_time = 0;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    err = cuda_allocBuffer((void**)&d_locations, sizeof(LatLong) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "Failed to allocate device memory for locations\n");
        exit(-1);
    }

    err = cuda_allocBuffer((void**)&d_distances, sizeof(float) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "Failed to allocate device memory for distances\n");
        exit(-1);
    }

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    // Copy data to device
    err = cuda_copyBufferToDevice(d_locations, &locations[0], sizeof(LatLong) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "Failed to copy locations to device\n");
        exit(-1);
    }

    // Setup kernel parameters
    int blockSize = 64;
    int numBlocks = (numRecords + blockSize - 1) / blockSize;

    // Launch kernel
    NearestNeighbor<<<numBlocks, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);

    err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        fprintf(stderr, "Kernel execution failed\n");
        exit(-1);
    }

    // Copy results back
    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Failed to allocate host memory for results\n");
        exit(-1);
    }

    err = cuda_copyBufferToHost(distances, d_distances, sizeof(float) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "Failed to copy distances to host\n");
        exit(-1);
    }

    if (timing) {
        printf("# Records\tAlloc(s)\t\tTotal(s)\n");
        printf("%d        \t%f\t\t-\n", numRecords, mem_alloc_time / 1000.0);
    }

    // Cleanup device memory
    cuda_freeBuffer(d_locations);
    cuda_freeBuffer(d_distances);

    return distances;
}

