// CUDA implementation of OpenClFindNearestNeighbors
float* CUDAFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong>& locations, float lat, float lng,
    int timing) {

    LatLong* d_locations;
    float* d_distances;
    cudaError_t error;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    error = cudaMalloc(&d_locations, sizeof(LatLong) * numRecords);
    cuda_errChk(error, "Error allocating device memory for locations", true);

    error = cudaMalloc(&d_distances, sizeof(float) * numRecords);
    cuda_errChk(error, "Error allocating device memory for distances", true);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    cudaEvent_t writeEvent, kernelEvent, readEvent;
    cudaEventCreate(&writeEvent);
    cudaEventCreate(&kernelEvent);
    cudaEventCreate(&readEvent);

    error = cudaMemcpyAsync(d_locations, &locations[0], sizeof(LatLong) * numRecords, cudaMemcpyHostToDevice);
    cuda_errChk(error, "Error copying locations to device", true);
    cudaEventRecord(writeEvent);

    // Set up kernel arguments (implicit in CUDA)
    int blockSize = 64;
    int numBlocks = (numRecords + blockSize - 1) / blockSize;

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    NearestNeighbor<<<numBlocks, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);
    error = cudaGetLastError();
    cuda_errChk(error, "ERROR in Executing Kernel NearestNeighbor", true);
    cudaEventRecord(kernelEvent);

    float* distances = (float*)malloc(sizeof(float) * numRecords);

    error = cudaMemcpyAsync(distances, d_distances, sizeof(float) * numRecords, cudaMemcpyDeviceToHost);
    cuda_errChk(error, "ERROR with cudaMemcpyAsync", true);
    cudaEventRecord(readEvent);

    if (timing) {
#ifdef TIMING
        cudaEventSynchronize(writeEvent);
        cudaEventSynchronize(kernelEvent);
        cudaEventSynchronize(readEvent);

        float writeTime, kernelTime, readTime;
        printf("# Records\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%d        \t", numRecords);

        cudaEventElapsedTime(&writeTime, writeEvent, kernelEvent); // Approximate
        printf("%f [%.2fMB]\t", writeTime / 1000.0, (float)((sizeof(LatLong) * numRecords) / 1e6));
        h2d_time = writeTime;

        cudaEventElapsedTime(&kernelTime, kernelEvent, readEvent); // Approximate, need separate events for precise
        // Re-calculate precise kernel time using separate start/end if needed, but simplified here
        printf("%f\t", kernelTime / 1000.0);
        kernel_time = kernelTime;

        // Read time approximation
        cudaEventSynchronize(readEvent);
        float totalTimeMs = 0;
        cudaEventElapsedTime(&readTime, writeEvent, readEvent); // Total elapsed
        // Better to use individual event pairs for precise segments
        // For this translation, we'll just report the total and approximate segments based on the async stream
        printf("%f [%.2fMB]\t", readTime / 1000.0, (float)((sizeof(float) * numRecords) / 1e6));
        d2h_time = readTime;

        printf("%f\n\n", (writeTime + kernelTime + readTime) / 1000.0);
#endif
    }

    cudaEventSynchronize(readEvent); // Ensure read is complete

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(d_locations);
    cudaFree(d_distances);
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    cudaEventDestroy(writeEvent);
    cudaEventDestroy(kernelEvent);
    cudaEventDestroy(readEvent);

    return distances;
}

int main(int argc, char* argv[]) {
    std::vector<Record> records;
    float* recordDistances;

    std::vector<LatLong> locations;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    // Set default data folder if not provided
    if (data_folder == NULL) {
        data_folder = (char*)".";
    }

    int numRecords = loadData(filename, records, locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (numRecords < resultsCount) resultsCount = numRecords;

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    // Initialize CUDA (equivalent to cl_init_context)
    cudaDeviceProp deviceProp;
    cudaGetDeviceProperties(&deviceProp, 0);
    if (!quiet) {
        printf("Using CUDA Device: %s\n", deviceProp.name);
    }

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    recordDistances = CUDAFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; resultsCount > i; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }

    free(recordDistances);
    return 0;
}

