	FILE * fp = fopen(tempchar, "rb");
	if (!fp) {
		printf("ERROR: unable to open '%s'\n", tempchar);
		return -1;
	}
	fread(source + strlen(source), sourcesize, 1, fp);
	fclose(fp);

	likelihood = (double *) malloc(sizeof (double) *Nparticles);
