__global__ void dynproc_kernel (int iteration,
                              int* gpuWall,
                              int* gpuSrc,
                              int* gpuResults,
                              int cols,
                              int rows,
                              int startStep,
                              int border,
                              int HALO,
                              int* outputBuffer)
{
    extern __shared__ int prev_shared[];
    int BLOCK_SIZE = blockDim.x;
    int* result_shared = &prev_shared[BLOCK_SIZE];

    int bx = blockIdx.x;
    int tx = threadIdx.x;

    int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

    int blkX = (small_block_cols*bx) - border;
    int blkXmax = blkX+BLOCK_SIZE-1;

    int xidx = blkX+tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

    int W = tx-1;
    int E = tx+1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool isValid = IN_RANGE(tx, validXmin, validXmax);

    if(IN_RANGE(xidx, 0, cols-1))
    {
        prev_shared[tx] = gpuSrc[xidx];
    }

    __syncthreads();

    bool computed;
    for (int i = 0; i < iteration; i++)
    {
        computed = false;

        if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
        {
            computed = true;
            int left = prev_shared[W];
            int up = prev_shared[tx];
            int right = prev_shared[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);

            int index = cols*(startStep+i)+xidx;
            result_shared[tx] = shortest + gpuWall[index];

            if (tx==11 && i==0)
            {
                int bufIndex = gpuSrc[xidx];
                if (bufIndex >= 0 && bufIndex < 16384) {
                    outputBuffer[bufIndex] = 1;
                }
            }
        }

        __syncthreads();

        if(i==iteration-1)
        {
            break;
        }

        if(computed)
        {
            prev_shared[tx] = result_shared[tx];
        }
        __syncthreads();
    }

    if (computed)
    {
        gpuResults[xidx] = result_shared[tx];
    }
}

