void 
write_graphics(	char* filename,
				fp* input, 
				int data_rows, 
				int data_cols, 
				int major,
				int data_range){

	FILE* fid;
	int i, j;

	fid = fopen(filename, "w");
	if( fid == NULL ){
		printf( "The file was not created/opened for writing\n" );
		return;
	}

	fprintf(fid, "P2\n");
	fprintf(fid, "%d %d\n", data_cols, data_rows);
	fprintf(fid, "%d\n", data_range);

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fprintf(fid, "%d ", (int)input[i*data_cols+j]);
			}
			fprintf(fid, "\n");
		}
	}
	else{
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fprintf(fid, "%d ", (int)input[j*data_rows+i]);
			}
			fprintf(fid, "\n");
		}
	}

	fclose(fid);
}

void 
read_graphics(	char* filename,
				fp* input,
				int data_rows, 
				int data_cols,
				int major){

	FILE* fid;
	int i, j;
	char c;
	int temp;

	fid = fopen(filename, "r");
	if( fid == NULL ){
		printf( "The file was not opened for reading\n" );
		return;
	}

	i = 0;
	while(i<3){
		c = fgetc(fid);
		if(c == '\n'){
			i = i+1;
		}
	};

	if(major==0){																
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%d", &temp);
				input[i*data_cols+j] = (fp)temp;
			}
		}
	}
	else{																				
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%d", &temp);
				input[j*data_rows+i] = (fp)temp;
			}
		}
	}

	fclose(fid);
}

void 
resize(	fp* input, 
		int input_rows,
		int input_cols,
		fp* output,
		int output_rows,
		int output_cols,
		int major){

	int i, j;
	int i2, j2;

	if(major == 0){																												

		for(i=0, i2=0; i<output_rows; i++, i2++){
			if(i2>=input_rows){
				i2 = i2 - input_rows;
			}
			for(j=0, j2=0; j<output_cols; j++, j2++){
				if(j2>=input_cols){
					j2 = j2 - input_cols;
				}
				output[i*output_cols+j] = input[i2*input_cols+j2];
			}
		}

	}

	else{																															

		for(j=0, j2=0; j<output_cols; j++, j2++){
			if(j2>=input_cols){
				j2 = j2 - input_cols;
			}
			for(i=0, i2=0; i<output_rows; i++, i2++){
				if(i2>=input_rows){
					i2 = i2 - input_rows;
				}
				output[j*output_rows+i] = input[j2*input_rows+i2];
			}
		}

	}
}

