			fp* d_dW, 
			fp* d_dE, 
			fp d_q0sqr, 
			fp* d_c, 
			fp* d_I){


    int bx = blockIdx.x;												
	int tx = threadIdx.x;												
	int ei = bx*NUMBER_THREADS+tx;											
	int row;																
