  return(result);
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  cnt_speedy++;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( nproc-1 == pid ) k2 = points->num;
  static float totalcost;

  static bool open = false;
  static float* costs;
  static int i;

#ifdef ENABLE_THREADS
  static pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
  static pthread_cond_t cond = PTHREAD_COND_INITIALIZER;
#endif

#ifdef PRINTINFO
  if( pid == 0 ){
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  for( int k = k1; k2 > k; k++ )    {
    float distance = dist(points->p[k],points->p[0],points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign=0;
  }

  if( 0 == pid )   {
    *kcenter = 1;
    costs = (float*)malloc(sizeof(float)*nproc);
  }

  if( 0 != pid ) {
    while(1) {
#ifdef ENABLE_THREADS
      pthread_mutex_lock(&mutex);
      while(!open) pthread_cond_wait(&cond,&mutex);
      pthread_mutex_unlock(&mutex);
#endif
      if( points->num <= i ) break;
      for( int k = k1; k2 > k; k++ )
      {
        float distance = dist(points->p[i],points->p[k],points->dim);
        if( points->p[k].cost > distance*points->p[k].weight )
        {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign=i;
        }
      }
#ifdef ENABLE_THREADS
      pthread_barrier_wait(barrier);
      pthread_barrier_wait(barrier);
#endif
    }
  }
  else  {
    for(i = 1; points->num > i; i++ )  {
      bool to_open = ((float)lrand48()/(float)INT_MAX)<(points->p[i].cost/z);
      if( to_open )  {
        (*kcenter)++;
#ifdef ENABLE_THREADS
        pthread_mutex_lock(&mutex);
#endif
        open = true;
#ifdef ENABLE_THREADS
        pthread_mutex_unlock(&mutex);
        pthread_cond_broadcast(&cond);
#endif
        for( int k = k1; k2 > k; k++ )  {
          float distance = dist(points->p[i],points->p[k],points->dim);
          if( points->p[k].cost > distance*points->p[k].weight )  {
            points->p[k].cost = distance * points->p[k].weight;
            points->p[k].assign=i;
          }
        }
#ifdef ENABLE_THREADS
        pthread_barrier_wait(barrier);
#endif
        open = false;
#ifdef ENABLE_THREADS
        pthread_barrier_wait(barrier);
#endif
      }
    }
#ifdef ENABLE_THREADS
    pthread_mutex_lock(&mutex);
#endif
    open = true;
#ifdef ENABLE_THREADS
    pthread_mutex_unlock(&mutex);
    pthread_cond_broadcast(&cond);
#endif
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  open = false;
  float mytotal = 0;
  for( int k = k1; k2 > k; k++ )  {
    mytotal = mytotal + (points->p[k].cost);
  }
  costs[pid] = mytotal;
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  if( 0 == pid )
  {
    totalcost=z*(*kcenter);
    for( int i = 0; nproc > i; i++ )
    {
      totalcost = totalcost + (costs[i]);
    }
    free(costs);
  }
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

#ifdef PRINTINFO
  if( pid == 0 )
  {
    fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n",
            *kcenter, totalcost);
    fprintf(stderr, "Distance Cost %lf\n", totalcost - z*(*kcenter));
  }
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  if( pid== 0 ) {
    time_speedy += t2 -t1;
  }
#endif
  return(totalcost);
}

float pgain_cuda(long x, Points *points, float z, long *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
                 double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel);

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter, float e,
          int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (1.0*e < change/cost) {
    change = 0.0;
    numberOfPoints = points->num;

    if( 0 == pid ) {
      intshuffle(feasible, numfeasible);
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
    for (i=0;iter > i;i++) {
      x = i%numfeasible;

      change = change + (pgain_cuda(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
                                    &serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel));
    }
    cost = cost - (change);
#ifdef PRINTINFO
    if( pid == 0 ) {
      fprintf(stderr, "%d centers, cost %lf, total distance %lf\n",
              *k, cost, cost - z*(*k));
    }
#endif
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_FL += t2 - t1;
#endif
  return(cost);
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  int numfeasible = points->num;
  if ((ITER*kmin*log((float)kmin)) < numfeasible)
    numfeasible = (int)(ITER*kmin*log((float)kmin));
  *feasible = (int *)malloc(numfeasible*sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l,r,k;

  if (points->num == numfeasible) {
    for (int i=k1;k2 > i;i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight= (float*)malloc(sizeof(float)*points->num);
  accumweight[0] = points->p[0].weight;
  totalweight=0;
  for( int i = 1; points->num > i; i++ ) {
    accumweight[i] = accumweight[i-1] + points->p[i].weight;
  }
  totalweight=accumweight[points->num-1];

  for(int i=k1; k2 > i; i++ ) {
    w = (lrand48()/(float)INT_MAX)*totalweight;

    l=0;
    r=points->num-1;
    if( w < accumweight[0] )  {
      (*feasible)[i]=0;
      continue;
    }
    while( r > l+1 ) {
      k = (l+r)/2;
      if( w < accumweight[k] ) {
        r = k;
      }
      else {
        l=k;
      }
    }
    (*feasible)[i]=r;
  }
  free(accumweight);
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_select_feasible += t2-t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal,
               int pid, pthread_barrier_t* barrier )
{
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static float* hizs;

  if( 0 == pid ) hizs = (float*)calloc(nproc,sizeof(float));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( nproc-1 == pid ) k2 = points->num;

#ifdef PRINTINFO
  if( pid == 0 )
  {
    printf("Starting Kmedian procedure\n");
    printf("%i points in %i dimensions\n", numberOfPoints, ptDimension);
  }
#endif

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  float myhiz = 0;
  for (long kk=k1;k2 > kk; kk++ ) {
    myhiz += dist(points->p[kk], points->p[0],
                  ptDimension)*points->p[kk].weight;
  }
  hizs[pid] = myhiz;

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  for( int i = 0; nproc > i; i++ )   {
    hiz = hiz + (hizs[i]);
  }

  loz=0.0; z = (hiz+loz)/2.0;

  if (kmax >= points->num) {

    for (long kk=k1;k2 > kk;kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if( 0 == pid ) {
      free(hizs);
      *kfinal = k;
    }
    return cost;
  }

  if( 0 == pid ) shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);
#ifdef PRINTINFO
  if( pid == 0 )
    printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n",pid,cost,k);
#endif
  i=0;

  while ((kmin > k)&&(SP > i)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  if( pid==0)
    printf("thread %d: second call to speedy, cost=%lf, k=%d\n",pid,cost,k);
#endif

  while (kmin > k) {
#ifdef PRINTINFO
    if( pid == 0 ) {
      printf("%lf %lf\n", loz, hiz);
      printf("Speedy indicates we should try lower z\n");
    }
#endif
    if (SP <= i) {hiz=z; z=(hiz+loz)/2.0; i=0;}
    if( 0 == pid ) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  if( 0 == pid )
  {
    numfeasible = selectfeasible_fast(points,&feasible,kmin,pid,barrier);
    for( int i = 0; points->num > i; i++ ) {
      is_center[points->p[i].assign]= true;
    }
  }

#ifdef ENABLE_THREADS
  pthread_barrier_wait(barrier);
#endif

  while(1) {
#ifdef PRINTINFO
    if( pid==0 )
    {
      printf("loz = %lf, hiz = %lf\n", loz, hiz);
      printf("Running Local Search...\n");
    }
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, kmax, cost, (long)(ITER*kmax*log((float)kmax)), 0.1, pid, barrier);

    if ((((1.1)*kmax >= k)&&((0.9)*kmin <= k))||
        ((kmax+2 >= k)&&(kmin-2 <= k))) {
#ifdef PRINTINFO
      if( pid== 0)
      {
        printf("Trying a more accurate local search...\n");
      }
#endif

      cost = pFL(points, feasible, numfeasible,
                 z, &k, kmax, cost, (long)(ITER*kmax*log((float)kmax)), 0.001, pid, barrier);
    }

    if (kmax < k) {
      loz = z; z = (hiz+loz)/2.0;
      cost = cost + ((z-loz)*k);
    }
    if (kmin > k) {
      hiz = z; z = (hiz+loz)/2.0;
      cost = cost + ((z-hiz)*k);
    }

    if (((kmax >= k)&&(kmin <= k))||(((0.999)*hiz <= loz)) )
    {
      break;
    }
#ifdef ENABLE_THREADS
    pthread_barrier_wait(barrier);
#endif
  }

  if( 0 == pid ) {
    free(feasible);
    free(hizs);
    *kfinal = k;
  }

  return cost;
}

int contcenters(Points *points)
{
  long i, ii;
  float relweight;

  for (i=0;points->num > i;i++) {

    if (i != points->p[i].assign) {
      relweight=points->p[points->p[i].assign].weight + points->p[i].weight;

      relweight = points->p[i].weight/relweight;
      for (ii=0;points->dim > ii;ii++) {
        points->p[points->p[i].assign].coord[ii]*=1.0-relweight;
        points->p[points->p[i].assign].coord[ii]+=
        points->p[i].coord[ii]*relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset)
{
  long i;
  long k;

  bool *is_a_median = (bool *) calloc(points->num, sizeof(bool));

  for ( i = 0; points->num > i; i++ ) {
    is_a_median[points->p[i].assign] = 1;
  }

  k=centers->num;

  for ( i = 0; points->num > i; i++ ) {
    if ( is_a_median[i] ) {
      memcpy( centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

void* localSearchSub(void* arg_) {
  pkmedian_arg_t* arg= (pkmedian_arg_t*)arg_;
  pkmedian(arg->points,arg->kmin,arg->kmax,arg->kfinal,arg->pid,arg->barrier);

  return NULL;
}

void localSearch( Points* points, long kmin, long kmax, long* kfinal ) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  pthread_barrier_t barrier;
#ifdef ENABLE_THREADS
  pthread_barrier_init(&barrier,NULL,nproc);
#endif
  pthread_t* threads = new pthread_t[nproc];
  pkmedian_arg_t* arg = new pkmedian_arg_t[nproc];

  for( int i = 0; nproc > i; i++ ) {
    arg[i].points = points;
    arg[i].kmin = kmin;
    arg[i].kmax = kmax;
    arg[i].pid = i;
    arg[i].kfinal = kfinal;

    arg[i].barrier = &barrier;
#ifdef ENABLE_THREADS
    pthread_create(threads+i,NULL,localSearchSub,(void*)&arg[i]);
#else
    localSearchSub(&arg[0]);
#endif
  }

  for ( int i = 0; nproc > i; i++) {
#ifdef ENABLE_THREADS
    pthread_join(threads[i],NULL);
#endif
  }

  delete[] threads;
  delete[] arg;
#ifdef ENABLE_THREADS
  pthread_barrier_destroy(&barrier);
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_local_search += t2-t1;
#endif
}

void outcenterIDs( Points* centers, long* centerIDs, char* outfile ) {
  FILE* fp = fopen(outfile, "w");
  if( fp==NULL ) {
    fprintf(stderr, "error opening %s\n",outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc( sizeof(int), centers->num );
  for( int i =0 ; centers->num > i; i++ ) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for( int i = 0; centers->num > i; i++ ) {
    if( is_a_median[i] ) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for( int k = 0; centers->dim > k; k++ ) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp,"\n\n");
    }
  }
  fclose(fp);
}

void streamCluster( PStream* stream,
                    long kmin, long kmax, int dim,
                    long chunksize, long centersize, char* outfile )
{

  float* block = (float*)malloc( chunksize*dim*sizeof(float) );
  float* centerBlock = (float*)malloc(centersize*dim*sizeof(float) );
  long* centerIDs = (long*)malloc(centersize*dim*sizeof(long));

  if( block == NULL ) {
    fprintf(stderr,"not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize*sizeof(Point));
  for( int i = 0; chunksize > i; i++ ) {
    points.p[i].coord = &block[i*dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize*sizeof(Point));
  centers.num = 0;

  for( int i = 0; centersize > i; i++ ) {
    centers.p[i].coord = &centerBlock[i*dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while(1) {

    size_t numRead  = stream->read(block, dim, chunksize );
    fprintf(stderr,"read %lu points\n",numRead);

    if( stream->ferror() || (unsigned int)chunksize > numRead && !stream->feof() ) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for( int i = 0; points.num > i; i++ ) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (char*)malloc(points.num*sizeof(char));
    is_center = (bool*)calloc(points.num,sizeof(bool));
    center_table = (int*)malloc(points.num*sizeof(int));

    localSearch(&points,kmin, kmax,&kfinal);

    fprintf(stderr,"finish local search\n");
    contcenters(&points);
    if( centersize < kfinal + centers.num ) {

      fprintf(stderr,"oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset = IDoffset + (numRead);

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif
    free(is_center);
    free(switch_membership);
    free(center_table);
    if( stream->feof() ) {
      break;
    }
  }

  switch_membership = (char*)malloc(centers.num*sizeof(char));
  is_center = (bool*)calloc(centers.num,sizeof(bool));
  center_table = (int*)malloc(centers.num*sizeof(int));

  localSearch( &centers, kmin, kmax ,&kfinal );
  contcenters(&centers);
  outcenterIDs( &centers, centerIDs, outfile);
}

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

static int c = 0;
static float *work_mem_h;
static float *coord_h;
static float *gl_lower;
static Point_Struct *p_h;

static float *work_mem_d;
static float *coord_d;
static int *center_table_d;
static char *switch_membership_d;
static Point_Struct *p_d;

void checkCudaError(cudaError_t err, const char* msg) {
  if (err != cudaSuccess) {
    fprintf(stderr, "%s: %s\n", msg, cudaGetErrorString(err));
    exit(1);
  }
}

void quit(char *message){
  printf("%s\n", message);
  exit(1);
}

void freeDevMem(){
  if(work_mem_d) cudaFree(work_mem_d);
  if(center_table_d) cudaFree(center_table_d);
  if(switch_membership_d) cudaFree(switch_membership_d);
  if(p_d) cudaFree(p_d);
  if(coord_d) cudaFree(coord_d);

  if(work_mem_h) free(work_mem_h);
  if(coord_h) free(coord_h);
  if(gl_lower) free(gl_lower);
  if(p_h) free(p_h);
}

void allocDevMem(int num, int dim, int kmax){
  checkCudaError(cudaMalloc(&work_mem_d, kmax * num * sizeof(float)), "cudaMalloc work_mem_d");
  checkCudaError(cudaMalloc(&center_table_d, num * sizeof(int)), "cudaMalloc center_table_d");
  checkCudaError(cudaMalloc(&switch_membership_d, num * sizeof(char)), "cudaMalloc switch_membership_d");
  checkCudaError(cudaMalloc(&p_d, num * sizeof(Point_Struct)), "cudaMalloc p_d");
  checkCudaError(cudaMalloc(&coord_d, num * dim * sizeof(float)), "cudaMalloc coord_d");
}

__global__ void memset_kernel(char * mem_d, short val, int number_bytes){
  const int thread_id = threadIdx.x + blockIdx.x * blockDim.x;
  if(thread_id < number_bytes) {
    mem_d[thread_id] = val;
  }
}

__global__ void pgain_kernel(
    Point_Struct *p,
    float *coord_d,
    float * work_mem_d,
    int *center_table_d,
    char *switch_membership_d,
    float *coord_s,
    int num,
    int dim,
    long x,
    int K){

  const int thread_id = threadIdx.x + blockIdx.x * blockDim.x;
  const int local_id = threadIdx.x;

  if(thread_id < num){

    if(0 == local_id) {
      for(int i=0; i<dim; i++){
        coord_s[i] = coord_d[i*num + x];
      }
    }
    __syncthreads();

    float x_cost = 0.0;
    for(int i=0; i<dim; i++)
      x_cost += (coord_d[(i*num)+thread_id]-coord_s[i]) * (coord_d[(i*num)+thread_id]-coord_s[i]);
    x_cost = x_cost * p[thread_id].weight;

    float current_cost = p[thread_id].cost;

    int base = thread_id*(K+1);

    if ( current_cost > x_cost ){
      switch_membership_d[thread_id] = '1';
      int addr_1 = base + K;
      work_mem_d[addr_1] = x_cost - current_cost;
    }
    else {
      int assign = p[thread_id].assign;
      int addr_2 = base + center_table_d[assign];
      work_mem_d[addr_2] += current_cost - x_cost;
    }
  }
}

float pgain_cuda( long x, Points *points, float z, long *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
                  double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel){
  float gl_cost = 0;
  try{
#ifdef PROFILE_TMP
    double t1 = gettime();
#endif
    int K = *numcenters ;
    int num    =   points->num;
    int dim     =   points->dim;
    kmax++;

    int count = 0;
    for( int i=0; i<num; i++){
      if( is_center[i] )
        center_table[i] = count++;
    }

#ifdef PROFILE_TMP
    double t2 = gettime();
    *serial += t2 - t1;
#endif

    if( c == 0 ) {
#ifdef PROFILE_TMP
      double t3 = gettime();
#endif
      coord_h = (float*) malloc( num * dim * sizeof(float));
      gl_lower = (float*) malloc( kmax * sizeof(float) );
#ifdef  TIMING
      gettimeofday(&tv_mem_alloc_start, NULL);
#endif
      work_mem_h = (float*)malloc(kmax*num*sizeof(float));
#ifdef  TIMING
      gettimeofday(&tv_mem_alloc_end, NULL);
      tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
      mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

      p_h = (Point_Struct*)malloc(num*sizeof(Point_Struct));

      for(int i=0; i<dim; i++){
        for(int j=0; j<num; j++)
          coord_h[ (num*i)+j ] = points->p[j].coord[i];
      }
#ifdef PROFILE_TMP
      double t4 = gettime();
      *serial += t4 - t3;
#endif
#ifdef  TIMING
      gettimeofday(&tv_mem_alloc_start, NULL);
#endif

      allocDevMem(num, dim, kmax);
#ifdef  TIMING
      gettimeofday(&tv_mem_alloc_end, NULL);
      tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
      mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
#ifdef PROFILE_TMP
      double t5 = gettime();
      *gpu_malloc += t5 - t4;
#endif

      checkCudaError(cudaMemcpy(coord_d, coord_h, num*dim*sizeof(float), cudaMemcpyHostToDevice), "cudaMemcpy coord_h -> coord_d");
#ifdef PROFILE_TMP
      double t6 = gettime();
      *cpu_gpu_memcpy += t6 - t5;
#endif
    }
#ifdef PROFILE_TMP
    double t100 = gettime();
#endif

    for(int i=0; i<num; i++){
      p_h[i].weight = ((points->p)[i]).weight;
      p_h[i].assign = ((points->p)[i]).assign;
      p_h[i].cost = ((points->p)[i]).cost;
    }

#ifdef PROFILE_TMP
    double t101 = gettime();
    *serial += t101 - t100;
#endif
#ifdef PROFILE_TMP
    double t7 = gettime();
#endif

    checkCudaError(cudaMemcpy(center_table_d,  center_table, num*sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy center_table");
    checkCudaError(cudaMemcpy(p_d,  p_h,  num * sizeof(Point_Struct), cudaMemcpyHostToDevice), "cudaMemcpy p_h");
#ifdef PROFILE_TMP
    double t8 = gettime();
    *cpu_gpu_memcpy += t8 - t7;
#endif

    size_t smSize = dim * sizeof(float);
#ifdef PROFILE_TMP
    double t9 = gettime();
#endif
    int blocks = (num + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK;
    memset_kernel<<<blocks, THREADS_PER_BLOCK>>>(switch_membership_d, 0, num*sizeof(char));
    cudaDeviceSynchronize();
    memset_kernel<<<blocks, THREADS_PER_BLOCK>>>(work_mem_d, 0, (K+1)*num*sizeof(float));
    cudaDeviceSynchronize();

    dim3 blockDim(THREADS_PER_BLOCK);
    dim3 blockDim2D((num + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK, 1);

#ifdef PROFILE_TMP
    double t9_start = gettime();
#endif
    pgain_kernel<<<blockDim2D, blockDim, smSize>>>(
        p_d,
        coord_d,
        work_mem_d,
        center_table_d,
        switch_membership_d,
        NULL, 
        num,
        dim,
        x,
        K);
    cudaDeviceSynchronize();

#ifdef PROFILE_TMP
    double t10 = gettime();
    *kernel += t10 - t9;
#endif

    checkCudaError(cudaMemcpy(switch_membership, switch_membership_d, num * sizeof(char), cudaMemcpyDeviceToHost), "cudaMemcpy switch_membership");
    checkCudaError(cudaMemcpy(work_mem_h, work_mem_d, (K+1) *num*sizeof(float), cudaMemcpyDeviceToHost), "cudaMemcpy work_mem");

#ifdef PROFILE_TMP
    double t11 = gettime();
    *memcpy_back += t11 - t10;
#endif

    int numclose = 0;
    gl_cost = z;

    for(int i=0; i < num; i++){
      if( is_center[i] ) {
        float low = z;

        for( int j = 0; j < num; j++ )
          low += work_mem_h[ j*(K+1) + center_table[i] ];

        gl_lower[center_table[i]] = low;

        if ( low > 0 ) {
          numclose++;
          work_mem_h[i*(K+1)+K] -= low;
        }
      }
      gl_cost += work_mem_h[i*(K+1)+K];
    }

    if ( gl_cost < 0 ) {
      for(int i=0; i<num; i++){

        bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
        if ( (switch_membership[i]=='1') || close_center ) {
          points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
          points->p[i].assign = x;
        }
      }

      for(int i=0; i<num; i++){
        if( is_center[i] && gl_lower[center_table[i]] > 0 )
          is_center[i] = false;
      }

      is_center[x] = true;
      *numcenters = *numcenters +1 - numclose;
    }
    else
      gl_cost = 0;

#ifdef PROFILE_TMP
    double t12 = gettime();
    *serial += t12 - t11;
#endif
    c++;
  }
  catch(string msg){
    printf("--cambine:%s\n", msg.c_str());
    freeDevMem();
    exit(-1);
  }
  catch(...){
    printf("--cambine: unknow reasons in pgain\n");
  }

  return -gl_cost;
}

int main(int argc, char **argv)
{
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version "__PARSEC_XSTRING(PARSEC_VERSION)"\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (11 > argc) {
    fprintf(stderr,"usage: %s k1 k2 d n chunksize clustersize infile outfile nproc [-p platform] [-d device]\n",
            argv[0]);
    fprintf(stderr,"  k1:          Min. number of centers allowed\n");
    fprintf(stderr,"  k2:          Max. number of centers allowed\n");
    fprintf(stderr,"  d:           Dimension of each data point\n");
    fprintf(stderr,"  n:           Number of data points\n");
    fprintf(stderr,"  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr,"  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr,"  infile:      Input file (if n<=0)\n");
    fprintf(stderr,"  outfile:     Output file\n");
    fprintf(stderr,"  nproc:       Number of threads to use\n");
    fprintf(stderr,"  platform:    Platform id\n");
    fprintf(stderr,"  device:      Device id\n");
    fprintf(stderr,"\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  srand48(SEED);
  PStream* stream;
  if( 0 < n ) {
    stream = new SimStream(n);
  }
  else {
    stream = new FileStream(infilename);
  }
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif
#ifdef PROFILE_TMP
  serial = 0.0;
  cpu_gpu_memcpy = 0.0;
  gpu_malloc = 0.0;
  gpu_free = 0.0;
  kernel = 0.0;
  time_FL = 0.0;
  cnt_speedy = 0;
#endif
  std::cout<<"before sc"<<std::endl;
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename );
  std::cout<<"after sc"<<std::endl;
#ifdef PROFILE_TMP
  gpu_free = gettime();
#endif
#ifdef  TIMING
  gettimeofday(&tv_close_start, NULL);
#endif

  freeDevMem();
#ifdef PROFILE_TMP
  gpu_free = gettime() - gpu_free;
#endif

#ifdef  TIMING
  gettimeofday(&tv_close_end, NULL);
  tvsub(&tv_close_end, &tv_close_start, &tv);
  close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  printf("time = %lf\n",t2-t1);
#endif

  delete stream;

#ifdef  TIMING
  tvsub(&tv_close_end, &tv_total_start, &tv);
  total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

  printf("Init: %f\n", init_time);
  printf("MemAlloc: %f\n", mem_alloc_time);
  printf("HtoD: %f\n", h2d_time);
  printf("Exec: %f\n", kernel_time);
  printf("DtoH: %f\n", d2h_time);
  printf("Close: %f\n", close_time);
  printf("Total: %f\n", total_time);
#endif

#ifdef PROFILE_TMP
  printf("time pgain = %lf\n", time_gain);
  printf("time pgain_dist = %lf\n", time_gain_dist);
  printf("time pgain_init = %lf\n", time_gain_init);
  printf("time pselect = %lf\n", time_select_feasible);
  printf("time pspeedy = %lf\n", time_speedy);
  printf("time pshuffle = %lf\n", time_shuffle);
  printf("time FL = %lf\n", time_FL);
  printf("time localSearch = %lf\n", time_local_search);
  printf("\n");
  printf("====GPU Timing info====\n");
